import { Card, Stack, Row, Text, Box, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city?: string;
  /** Current temperature */
  temperature?: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition?: string;
  /** Humidity percentage */
  humidity?: number;
  /** Wind speed */
  windSpeed?: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast?: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

const defaultForecast = [
  { day: "Mon", icon: "☀️", high: 75, low: 62 },
  { day: "Tue", icon: "☁️", high: 70, low: 60 },
  { day: "Wed", icon: "🌧️", high: 68, low: 58 },
  { day: "Thu", icon: "☁️", high: 72, low: 61 },
  { day: "Fri", icon: "☀️", high: 76, low: 64 },
];

export default function WeatherCard({
  city = "Unknown",
  temperature = 72,
  condition = "Clear",
  humidity = 50,
  windSpeed = 10,
  unit = "°F",
  forecast = defaultForecast,
}: Props) {
  return (
    <Card
      padding={24}
      shadow="md"
      border={true}
      style={{ backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)' }}
    >
      {/* HEADER SECTION */}
      <Stack direction="vertical" gap={12} align="start">
        {/* City Title */}
        <Text
          variant="h3"
          color="var(--ggui-color-onSurface, #18181b)"
          weight="semibold"
        >
          {city}
        </Text>

        {/* Temperature + Condition Row */}
        <Row gap={16} align="center">
          <Text
            variant="h1"
            weight="bold"
            color="var(--ggui-color-primary-600, #0284c7)"
            style={{ fontSize: 'var(--ggui-font-size-4xl, 36px)' }}
          >
            {temperature}
            {unit}
          </Text>
          <Stack direction="vertical" gap={4}>
            <Text
              variant="body"
              weight="medium"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {condition}
            </Text>
          </Stack>
        </Row>
      </Stack>

      <Divider margin={16} />

      {/* METRICS SECTION */}
      <Row
        gap={32}
        justify="start"
        align="stretch"
        style={{ marginBottom: 'var(--ggui-spacing-4, 16px)' }}
      >
        {/* Humidity */}
        <Stack direction="vertical" gap={4}>
          <Text
            variant="label"
            weight="medium"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            Humidity
          </Text>
          <Text
            variant="body"
            weight="semibold"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            {humidity}%
          </Text>
        </Stack>

        {/* Wind Speed */}
        <Stack direction="vertical" gap={4}>
          <Text
            variant="label"
            weight="medium"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            Wind Speed
          </Text>
          <Text
            variant="body"
            weight="semibold"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            {windSpeed} mph
          </Text>
        </Stack>
      </Row>

      <Divider margin={16} />

      {/* FORECAST SECTION */}
      <Row
        gap={8}
        wrap={true}
        align="stretch"
        justify="start"
        style={{
          display: 'flex',
          flexWrap: 'wrap',
          gap: 'var(--ggui-spacing-2, 8px)',
        }}
      >
        {(forecast || defaultForecast).map((item, index) => (
          <Box
            key={index}
            padding={12}
            borderRadius="var(--ggui-shape-radius-md, 8px)"
            style={{
              backgroundColor: 'var(--ggui-color-primary-100, #e0f2fe)',
              border: '1px solid var(--ggui-color-primary-200, #bae6fd)',
              minWidth: '80px',
              flex: '0 0 auto',
            }}
          >
            <Stack direction="vertical" gap={8} align="center">
              {/* Day name */}
              <Text
                variant="label"
                weight="semibold"
                color="var(--ggui-color-onSurface, #18181b)"
              >
                {item.day || "—"}
              </Text>

              {/* Weather icon */}
              <Text
                style={{
                  fontSize: '24px',
                  lineHeight: 1,
                  color: 'currentColor',
                }}
              >
                {item.icon || "❓"}
              </Text>

              {/* High/Low temps */}
              <Row gap={4} align="center" justify="center">
                <Text
                  variant="caption"
                  weight="semibold"
                  color="var(--ggui-color-onSurface, #18181b)"
                >
                  {item.high ?? "—"}°
                </Text>
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  {item.low ?? "—"}°
                </Text>
              </Row>
            </Stack>
          </Box>
        ))}
      </Row>
    </Card>
  );
}

