import { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Badge,
  Box,
  MotionKeyframes,
  useMotion,
  Toast,
} from '@ggui-ai/design/primitives';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<Stock>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

// Default stock data for demo/preview
const DEFAULT_STOCKS: Stock[] = [
  { symbol: 'AAPL', name: 'Apple Inc.', price: 150.25, change: 2.50, changePercent: 1.69 },
  { symbol: 'MSFT', name: 'Microsoft Corp.', price: 375.00, change: -1.50, changePercent: -0.40 },
  { symbol: 'GOOGL', name: 'Alphabet Inc.', price: 2800.00, change: 15.00, changePercent: 0.54 },
  { symbol: 'AMZN', name: 'Amazon.com Inc.', price: 180.50, change: 0.00, changePercent: 0.00 },
  { symbol: 'TSLA', name: 'Tesla Inc.', price: 245.30, change: -8.20, changePercent: -3.23 },
  { symbol: 'META', name: 'Meta Platforms Inc.', price: 310.75, change: 5.50, changePercent: 1.80 },
];

/**
 * Determine color based on change sentiment
 */
function getChangeColor(changePercent?: number): {
  text: string;
  border: string;
  bg: string;
} {
  if (changePercent === undefined || changePercent === null) {
    return {
      text: 'var(--ggui-color-onSurfaceVariant, #52525b)',
      border: 'var(--ggui-color-outline, #d4d4d8)',
      bg: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
    };
  }

  if (changePercent > 0) {
    return {
      text: 'var(--ggui-color-success-500, #22c55e)',
      border: 'var(--ggui-color-success-500, #22c55e)',
      bg: 'var(--ggui-color-success-50, #f0fdf4)',
    };
  }

  if (changePercent < 0) {
    return {
      text: 'var(--ggui-color-error-500, #ef4444)',
      border: 'var(--ggui-color-error-500, #ef4444)',
      bg: 'var(--ggui-color-error-50, #fef2f2)',
    };
  }

  return {
    text: 'var(--ggui-color-onSurfaceVariant, #52525b)',
    border: 'var(--ggui-color-outline, #d4d4d8)',
    bg: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
  };
}

/**
 * Get arrow symbol based on change direction
 */
function getArrowSymbol(changePercent?: number): string {
  if (changePercent === undefined || changePercent === null || changePercent === 0) {
    return '─';
  }
  return changePercent > 0 ? '▲' : '▼';
}

/**
 * Format price with 2 decimals and $ symbol
 */
function formatPrice(price?: number): string {
  if (price === undefined || price === null) {
    return '$0.00';
  }
  return `$${price.toFixed(2)}`;
}

/**
 * Format change with sign and 2 decimals
 */
function formatChange(change?: number): string {
  if (change === undefined || change === null) {
    return '$0.00';
  }
  const sign = change > 0 ? '+' : '';
  return `${sign}$${Math.abs(change).toFixed(2)}`;
}

/**
 * Format change percent with % sign
 */
function formatChangePercent(changePercent?: number): string {
  if (changePercent === undefined || changePercent === null) {
    return '0.00%';
  }
  const sign = changePercent > 0 ? '+' : '';
  return `${sign}${Math.abs(changePercent).toFixed(2)}%`;
}

/**
 * Format ISO timestamp to readable string
 */
function formatTimestamp(isoString?: string): string {
  if (!isoString) {
    return new Date().toLocaleString();
  }
  try {
    return new Date(isoString).toLocaleString();
  } catch {
    return '--:--';
  }
}

/**
 * Individual Stock Card Component
 */
function StockCard({
  stock,
  index = 0,
  motionEnabled = true,
}: {
  stock: Stock;
  index?: number;
  motionEnabled?: boolean;
}) {
  const changeColor = getChangeColor(stock.changePercent);
  const arrow = getArrowSymbol(stock.changePercent);

  return (
    <Card
      padding="16"
      shadow="sm"
      border={true}
      style={{
        borderColor: changeColor.border,
        borderWidth: '1px',
        animation: motionEnabled
          ? `ggui-slideInUp 300ms ease-out forwards`
          : 'none',
        animationDelay: motionEnabled ? `${index * 50}ms` : '0ms',
      }}
      role="listitem"
    >
      <Stack direction="vertical" gap={12} align="stretch">
        {/* Ticker and status badge */}
        <Row justify="between" align="center" gap={8}>
          <Text
            variant="h3"
            weight="bold"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            {stock.symbol || 'N/A'}
          </Text>
          <Badge variant="primary" size="sm" pill>
            ACTIVE
          </Badge>
        </Row>

        {/* Company name */}
        <Text
          variant="body"
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
        >
          {stock.name || 'Unknown Company'}
        </Text>

        {/* Price section */}
        <Row align="baseline" gap={8}>
          <Text
            variant="h2"
            weight="bold"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            {formatPrice(stock.price)}
          </Text>
          <Badge variant="default" size="sm" pill>
            USD
          </Badge>
        </Row>

        {/* Change section */}
        <Stack direction="vertical" gap={4}>
          <Text
            variant="label"
            color={changeColor.text}
            weight="semibold"
            aria-label={`Change: ${formatChange(stock.change)}`}
          >
            {formatChange(stock.change)}
          </Text>
          <Row align="center" gap={4}>
            <Text
              variant="label"
              color={changeColor.text}
              weight="semibold"
              aria-label={`Change percentage: ${formatChangePercent(stock.changePercent)}`}
            >
              <span style={{ marginRight: '4px' }}>{arrow}</span>
              {formatChangePercent(stock.changePercent)}
            </Text>
          </Row>
        </Stack>
      </Stack>
    </Card>
  );
}

/**
 * Connection Status Badge
 */
function ConnectionBadge({
  status,
}: {
  status: 'idle' | 'connecting' | 'connected' | 'error';
}) {
  const statusConfig = {
    connected: {
      color: 'var(--ggui-color-success-500, #22c55e)',
      label: 'Live',
    },
    connecting: {
      color: 'var(--ggui-color-warning-500, #f59e0b)',
      label: 'Connecting...',
    },
    error: {
      color: 'var(--ggui-color-error-500, #ef4444)',
      label: 'Offline',
    },
    idle: {
      color: 'var(--ggui-color-neutral-500, #6b7280)',
      label: 'Idle',
    },
  };

  const config = statusConfig[status];

  return (
    <Box
      style={{
        display: 'flex',
        alignItems: 'center',
        gap: 'var(--ggui-spacing-2, 8px)',
        padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-3, 12px)',
        borderRadius: 'var(--ggui-shape-radius-md, 8px)',
        backgroundColor:
          status === 'connected'
            ? 'var(--ggui-color-success-50, #f0fdf4)'
            : status === 'error'
              ? 'var(--ggui-color-error-50, #fef2f2)'
              : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
      }}
    >
      <div
        style={{
          width: 'var(--ggui-spacing-1, 8px)',
          height: 'var(--ggui-spacing-1, 8px)',
          borderRadius: '50%',
          backgroundColor: config.color,
          animation:
            status === 'connecting' ? 'pulse 2s cubic-bezier(0.4, 0, 0.6, 1) infinite' : 'none',
        }}
      />
      <Text
        variant="caption"
        color={config.color}
        weight="semibold"
      >
        {config.label}
      </Text>
    </Box>
  );
}

/**
 * Main Stock Ticker Dashboard Component
 */
export default function StockTickerDashboard({
  stocks: propStocks = DEFAULT_STOCKS,
  lastUpdated: propLastUpdated,
}: Props) {
  const { motionEnabled } = useMotion();
  const [stocks, setStocks] = useState<Stock[]>(propStocks);
  const [lastUpdated, setLastUpdated] = useState<string>(
    propLastUpdated || new Date().toISOString()
  );
  const [connectionStatus, setConnectionStatus] = useState<
    'idle' | 'connecting' | 'connected' | 'error'
  >('idle');
  const [errorMessage, setErrorMessage] = useState<string>('');

  // Stream listener for real-time data updates
  useEffect(() => {
    // Initialize connecting state
    setConnectionStatus('connecting');

    const handleAgentData = (event: Event) => {
      try {
        const customEvent = event as CustomEvent;
        const data = customEvent.detail;

        if (data && Array.isArray(data.stocks)) {
          setStocks(data.stocks);
          if (data.timestamp) {
            setLastUpdated(data.timestamp);
          }
          setConnectionStatus('connected');
          setErrorMessage('');
        }
      } catch (err) {
        console.error('Error processing agent data:', err);
        setConnectionStatus('error');
        setErrorMessage('Failed to process stock data');
      }
    };

    // Listen for ggui:agent-data events via event delegation
    const eventTarget = typeof document !== 'undefined' ? document : null;
    if (eventTarget) {
      eventTarget.addEventListener('ggui:agent-data', handleAgentData);
      return () => {
        eventTarget.removeEventListener('ggui:agent-data', handleAgentData);
      };
    }
  }, []);

  return (
    <Container maxWidth="xl" padding="24" center={true}>
      <MotionKeyframes />

      <Stack direction="vertical" gap={16} align="stretch">
        {/* Header with title and timestamp */}
        <Card padding="16" shadow="sm" border={true}>
          <Row justify="between" align="center" gap={12}>
            <Text
              variant="h2"
              weight="bold"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              Market Watch
            </Text>
            <Stack direction="vertical" align="end" gap={4}>
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Last Updated:
              </Text>
              <Text
                variant="label"
                color="var(--ggui-color-onSurface, #18181b)"
                weight="semibold"
              >
                {formatTimestamp(lastUpdated)}
              </Text>
            </Stack>
          </Row>
        </Card>

        {/* Connection status indicator */}
        {connectionStatus !== 'idle' && (
          <ConnectionBadge status={connectionStatus} />
        )}

        {/* Stock cards grid */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))',
            gap: 'var(--ggui-spacing-4, 16px)',
          }}
          role="list"
        >
          {stocks && stocks.length > 0 ? (
            stocks.map((stock, index) => (
              <StockCard
                key={stock.symbol || index}
                stock={stock}
                index={index}
                motionEnabled={motionEnabled}
              />
            ))
          ) : (
            <Box
              style={{
                gridColumn: '1 / -1',
                display: 'flex',
                justifyContent: 'center',
                alignItems: 'center',
                padding: 'var(--ggui-spacing-6, 24px)',
              }}
            >
              <Text
                variant="body"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
                align="center"
              >
                {connectionStatus === 'connecting'
                  ? 'Loading stocks...'
                  : 'No stocks available'}
              </Text>
            </Box>
          )}
        </Box>

        {/* Error toast */}
        {errorMessage && (
          <Toast
            variant="error"
            title="Connection Error"
            message={errorMessage}
            duration={0}
            onClose={() => setErrorMessage('')}
            visible={true}
          />
        )}
      </Stack>

      {/* Pulse animation for connecting state */}
      <style>{`
        @keyframes pulse {
          0%, 100% {
            opacity: 1;
          }
          50% {
            opacity: 0.5;
          }
        }
      `}</style>
    </Container>
  );
}

import { Container, Card, Box, Stack, Row, Text, Divider, Badge, MotionKeyframes, useMotion } from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

function getConditionEmoji(condition: string): string {
  const c = condition.toLowerCase();
  if (c === 'sunny' || c === 'clear') return '☀️';
  if (c === 'partly cloudy') return '⛅';
  if (c === 'cloudy' || c === 'overcast') return '☁️';
  if (c === 'rainy' || c === 'rain') return '🌧️';
  if (c === 'stormy' || c === 'thunderstorm') return '⛈️';
  if (c === 'snowy' || c === 'snow') return '🌨️';
  if (c === 'foggy' || c === 'fog' || c === 'mist') return '🌫️';
  if (c === 'windy') return '💨';
  return '🌤️';
}

