import { useState } from 'react';
import {
  Container, Card, Box, Stack, Row, Text, Input, TextArea,
  Checkbox, RadioGroup, Button, Divider, Badge, Icon, Toast,
  MotionKeyframes, useMotion
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface SurveyData {
  name: string;
  email: string;
  satisfaction: string;
  satisfactionLabel: string;
  selectedFeatures: string[];
  comments: string;
}

interface Props {
  featureOptions: string[];
  satisfactionLabels: string[];
  onSubmit?: (data: SurveyData) => void | Promise<void>;
}

const TOTAL_STEPS = 4;
const STEP_LABELS = ['Your Info', 'Satisfaction', 'Features', 'Comments'];
const MAX_COMMENTS = 500;
const EMAIL_REGEX = /^[^@\s]+@[^@\s]+\.[^@\s]+$/;

export default function GeneratedComponent({
  featureOptions = ['Dashboard', 'Reporting', 'API Access', 'Mobile App', 'Integrations'],
  satisfactionLabels = ['Very Unsatisfied', 'Unsatisfied', 'Neutral', 'Satisfied', 'Very Satisfied'],
  onSubmit,
}: Props) {
  const { motionEnabled } = useMotion();
  const [step, setStep] = useState(0);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [selectedFeatures, setSelectedFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');
  const [touched, setTouched] = useState<Record<string, boolean>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [submitStatus, setSubmitStatus] = useState<'idle' | 'success' | 'error'>('idle');
  const [animKey, setAnimKey] = useState(0);

  const validateName = (v: string) => (!v.trim() ? 'Name is required' : '');
  const validateEmail = (v: string) => {
    if (!v.trim()) return 'Email is required';
    if (!EMAIL_REGEX.test(v)) return 'Please enter a valid email address';
    return '';
  };

  const nameError = touched.name ? validateName(name) : '';
  const emailError = touched.email ? validateEmail(email) : '';

  const isStepValid = (s: number): boolean => {
    switch (s) {
      case 0: return !validateName(name) && !validateEmail(email);
      case 1: return satisfaction !== '';
      case 2: return true;
      case 3: return true;
      case 4: return true;
      default: return false;
    }
  };

  const handleNameChange = (value: string) => {
    setName(value);
    if (!touched.name) setTouched(prev => ({ ...prev, name: true }));
  };

  const handleEmailChange = (value: string) => {
    setEmail(value);
    if (!touched.email) setTouched(prev => ({ ...prev, email: true }));
  };

  const handleFeatureToggle = (feature: string, checked: boolean) => {
    setSelectedFeatures(prev =>
      checked ? [...prev, feature] : prev.filter(f => f !== feature)
    );
  };

  const handleCommentsChange = (value: string) => {
    if (value.length <= MAX_COMMENTS) setComments(value);
  };

  const goNext = () => {
    if (step === 0) {
      setTouched({ name: true, email: true });
      if (!isStepValid(0)) return;
    }
    if (step < TOTAL_STEPS && isStepValid(step)) {
      setStep(s => s + 1);
      setAnimKey(k => k + 1);
    }
  };

  const goBack = () => {
    if (step > 0) {
      setStep(s => s - 1);
      setAnimKey(k => k + 1);
    }
  };

  const handleSubmit = async () => {
    if (isSubmitting) return;
    setIsSubmitting(true);
    setSubmitStatus('idle');
    const satisfactionIndex = parseInt(satisfaction, 10) - 1;
    const satisfactionLabel = satisfactionLabels[satisfactionIndex] || satisfaction;
    const data: SurveyData = {
      name: name.trim(),
      email: email.trim(),
      satisfaction,
      satisfactionLabel,
      selectedFeatures,
      comments: comments.trim(),
    };
    try {
      if (onSubmit) await onSubmit(data);
      setSubmitStatus('success');
    } catch {
      setSubmitStatus('error');
    } finally {
      setIsSubmitting(false);
    }
  };

  const progressPercent = ((step + 1) / (TOTAL_STEPS + 1)) * 100;
  const isReviewStep = step === TOTAL_STEPS;
  const currentStepLabel = isReviewStep ? 'Review' : STEP_LABELS[step];
  const satisfactionOptions = satisfactionLabels.map((label, index) => ({
    value: String(index + 1),
    label: `${index + 1} — ${label}`,
  }));
  const canProceed = isStepValid(step);
  const satisfactionIndexForReview = parseInt(satisfaction, 10) - 1;
  const satisfactionLabelForReview = satisfactionLabels[satisfactionIndexForReview] || '';

  const stepContent = (() => {
    switch (step) {
      case 0:
        return (
          <Stack direction="vertical" gap={16}>
            <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">Tell us about yourself</Text>
            <Input label="Full Name" placeholder="Enter your full name" value={name} onChange={handleNameChange} required error={nameError} disabled={isSubmitting} />
            <Input label="Email Address" type="email" placeholder="you@example.com" value={email} onChange={handleEmailChange} required error={emailError} disabled={isSubmitting} />
          </Stack>
        );
      case 1:
        return (
          <Stack direction="vertical" gap={16}>
            <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">How satisfied are you?</Text>
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              Please rate your overall satisfaction on a scale of 1 to {satisfactionLabels.length}.
            </Text>
            <RadioGroup label="Satisfaction Rating" value={satisfaction} onChange={setSatisfaction} options={satisfactionOptions} direction="vertical" disabled={isSubmitting} />
          </Stack>
        );
      case 2:
        return (
          <Stack direction="vertical" gap={16}>
            <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">Which features interest you?</Text>
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Select all that apply. This step is optional.</Text>
            <Stack direction="vertical" gap={8}>
              {featureOptions.map(feature => (
                <Checkbox
                  key={feature}
                  label={feature}
                  checked={selectedFeatures.includes(feature)}
                  onChange={(checked) => handleFeatureToggle(feature, checked)}
                  disabled={isSubmitting}
                />
              ))}
            </Stack>
          </Stack>
        );
      case 3:
        return (
          <Stack direction="vertical" gap={16}>
            <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">Any additional comments?</Text>
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Share any thoughts, suggestions, or feedback. This is optional.</Text>
            <Stack direction="vertical" gap={4}>
              <TextArea label="Comments" placeholder="Type your comments here..." value={comments} onChange={handleCommentsChange} rows={5} maxLength={MAX_COMMENTS} disabled={isSubmitting} />
              <div aria-live="polite">
                <Text
                  variant="caption"
                  align="right"
                  color={comments.length > MAX_COMMENTS * 0.9 ? 'var(--ggui-color-error-500, #ef4444)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                >
                  {comments.length} / {MAX_COMMENTS} characters
                </Text>
              </div>
            </Stack>
          </Stack>
        );
      case 4:
        return (
          <Stack direction="vertical" gap={16}>
            <Text variant="h3" color="var(--ggui-color-onSurface, #18181b)">Review Your Answers</Text>
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Please review your responses before submitting.</Text>
            <Box background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="var(--ggui-shape-radius-md, 8px)" padding={16}>
              <Stack direction="vertical" gap={8}>
                <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)" weight="semibold">Personal Information</Text>
                <Row gap={8}>
                  <Text weight="semibold" color="var(--ggui-color-onSurfaceVariant, #52525b)">Name:</Text>
                  <Text color="var(--ggui-color-onSurface, #18181b)">{name}</Text>
                </Row>
                <Row gap={8}>
                  <Text weight="semibold" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email:</Text>
                  <Text color="var(--ggui-color-onSurface, #18181b)">{email}</Text>
                </Row>
              </Stack>
            </Box>
            <Box background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="var(--ggui-shape-radius-md, 8px)" padding={16}>
              <Stack direction="vertical" gap={8}>
                <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)" weight="semibold">Satisfaction Rating</Text>
                <Row gap={8} align="center">
                  <Badge variant="primary" size="sm">{satisfaction}</Badge>
                  <Text color="var(--ggui-color-onSurface, #18181b)">{satisfactionLabelForReview}</Text>
                </Row>
              </Stack>
            </Box>
            <Box background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="var(--ggui-shape-radius-md, 8px)" padding={16}>
              <Stack direction="vertical" gap={8}>
                <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)" weight="semibold">Feature Interests</Text>
                {selectedFeatures.length > 0 ? (
                  <Row gap={8} wrap>
                    {selectedFeatures.map(feature => (
                      <Badge key={feature} variant="secondary" size="sm">{feature}</Badge>
                    ))}
                  </Row>
                ) : (
                  <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">No features selected</Text>
                )}
              </Stack>
            </Box>
            <Box background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="var(--ggui-shape-radius-md, 8px)" padding={16}>
              <Stack direction="vertical" gap={8}>
                <Text variant="label" color="var(--ggui-color-primary-700, #0369a1)" weight="semibold">Additional Comments</Text>
                <Text color="var(--ggui-color-onSurface, #18181b)">{comments.trim() || 'No comments provided'}</Text>
              </Stack>
            </Box>
          </Stack>
        );
      default:
        return null;
    }
  })();

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="md">
        <div role="form" aria-label="Multi-step survey">
          <Card padding={24} shadow="md">
            <Stack direction="vertical" gap={24}>

              {/* Header */}
              <Text variant="h2" align="center" color="var(--ggui-color-onSurface, #18181b)">Survey</Text>

              {/* Progress bar */}
              <Stack direction="vertical" gap={8}>
                <Row justify="between" align="center">
                  <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                    {isReviewStep ? 'Review & Submit' : `Step ${step + 1} of ${TOTAL_STEPS}`}
                  </Text>
                  <Text variant="caption" weight="semibold" color="var(--ggui-color-primary-600, #0284c7)">
                    {currentStepLabel}
                  </Text>
                </Row>
                <div
                  role="progressbar"
                  aria-valuenow={Math.round(progressPercent)}
                  aria-valuemin={0}
                  aria-valuemax={100}
                  aria-label="Survey progress"
                  style={{
                    width: '100%',
                    height: 8,
                    backgroundColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
                    borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                    overflow: 'hidden',
                  }}
                >
                  <div style={{
                    width: `${progressPercent}%`,
                    height: '100%',
                    backgroundColor: 'var(--ggui-color-primary-600, #0284c7)',
                    borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                    transition: 'width 300ms cubic-bezier(0.4, 0, 0.2, 1)',
                  }} />
                </div>
              </Stack>

              {/* Step indicators */}
              <Row gap={4} justify="center" align="center">
                {STEP_LABELS.map((label, i) => {
                  const isCompleted = i < step || isReviewStep;
                  const isActive = i === step && !isReviewStep;
                  const isFuture = i > step && !isReviewStep;
                  return (
                    <Row key={label} gap={4} align="center">
                      {i > 0 && (
                        <div style={{
                          width: 24,
                          height: 2,
                          backgroundColor: isCompleted
                            ? 'var(--ggui-color-primary-600, #0284c7)'
                            : 'var(--ggui-color-outlineVariant, #e4e4e7)',
                          transition: transition.colors,
                        }} />
                      )}
                      <Stack direction="vertical" align="center" gap={4}>
                        <div
                          aria-label={`Step ${i + 1}: ${label}${isCompleted ? ' (completed)' : isActive ? ' (current)' : ''}`}
                          style={{
                            width: 32,
                            height: 32,
                            borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                            display: 'flex',
                            alignItems: 'center',
                            justifyContent: 'center',
                            fontSize: 'var(--ggui-font-size-xs, 12px)',
                            fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                            flexShrink: 0,
                            transition: transition.colors,
                            backgroundColor: isCompleted
                              ? 'var(--ggui-color-success-600, #16a34a)'
                              : isActive
                                ? 'var(--ggui-color-primary-600, #0284c7)'
                                : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                            color: (isCompleted || isActive)
                              ? 'var(--ggui-color-surface, #fafafa)'
                              : 'var(--ggui-color-onSurfaceVariant, #52525b)',
                            border: isFuture
                              ? '2px solid var(--ggui-color-outline, #d4d4d8)'
                              : 'none',
                            boxSizing: 'border-box' as const,
                          }}
                        >
                          {isCompleted ? <Icon name="check" size={14} /> : i + 1}
                        </div>
                        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                          {label}
                        </Text>
                      </Stack>
                    </Row>
                  );
                })}
              </Row>

              <Divider margin={8} />

              {/* Step content (animated) */}
              <div
                key={animKey}
                role="group"
                aria-label={isReviewStep ? 'Review your answers' : `Step ${step + 1}: ${STEP_LABELS[step]}`}
                aria-live="polite"
                style={{ animation: motionEnabled ? animation.fadeIn : 'none' }}
              >
                {stepContent}
              </div>

              <Divider margin={8} />

              {/* Navigation */}
              <Row justify="between" align="center">
                {step > 0 ? (
                  <Button
                    variant="outline"
                    onClick={goBack}
                    disabled={isSubmitting}
                    leftIcon={<Icon name="chevron-left" size={16} />}
                  >
                    Back
                  </Button>
                ) : (
                  <div />
                )}
                {isReviewStep ? (
                  <Button
                    variant="primary"
                    onClick={handleSubmit}
                    disabled={isSubmitting}
                    loading={isSubmitting}
                    leftIcon={!isSubmitting ? <Icon name="check" size={16} /> : undefined}
                  >
                    {isSubmitting ? 'Submitting...' : 'Submit Survey'}
                  </Button>
                ) : (
                  <Button
                    variant="primary"
                    onClick={goNext}
                    disabled={!canProceed || isSubmitting}
                    rightIcon={<Icon name="chevron-right" size={16} />}
                  >
                    Next
                  </Button>
                )}
              </Row>

            </Stack>
          </Card>
        </div>
      </Container>

      <Toast
        visible={submitStatus === 'success'}
        variant="success"
        title="Survey Submitted"
        message="Thank you for your feedback! Your responses have been recorded."
        onClose={() => setSubmitStatus('idle')}
        duration={5000}
      />
      <Toast
        visible={submitStatus === 'error'}
        variant="error"
        title="Submission Failed"
        message="Something went wrong. Please try again."
        onClose={() => setSubmitStatus('idle')}
        duration={5000}
      />
    </>
  );
}

import { useState, useEffect, useRef, useCallback } from 'react';
import {
  Container, Card, Row, Text, Badge, Input, Button, Icon, MotionKeyframes, useMotion
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface MessageItem {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
}

function formatTimestamp(iso?: string): string {
  if (!iso) return '';
  try {
    const date = new Date(iso);
    return date.toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });
  } catch {
    return '';
  }
}

export default function GeneratedComponent({
  title = 'Team Chat',
  currentUser = 'You',
  participantCount = 3,
  messages = [
    { sender: 'Alice', text: 'Hey team! How is the project going?', timestamp: '2024-01-15T09:00:00Z' },
    { sender: 'Alice', text: 'I just pushed the latest changes.', timestamp: '2024-01-15T09:00:30Z' },
    { sender: 'You', text: 'Looking great! I will review the PR shortly.', timestamp: '2024-01-15T09:01:00Z' },
    { sender: 'Bob', text: 'Nice work everyone! 🎉', timestamp: '2024-01-15T09:02:00Z' },
  ],
}: Props) {
  const [inputText, setInputText] = useState('');
  const [streamedMessages, setStreamedMessages] = useState<MessageItem[]>([]);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const rootRef = useRef<HTMLDivElement>(null);
  const { motionEnabled } = useMotion();

  const allMessages: MessageItem[] = [...messages, ...streamedMessages];

  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [allMessages.length, scrollToBottom]);

  // Stream Contract: listen for ggui:agent-data via the root element's ownerDocument
  useEffect(() => {
    const el = rootRef.current;
    if (!el) return;
    const target = el.ownerDocument;
    const handler = (event: Event) => {
      const detail = (event as CustomEvent).detail;
      if (detail && typeof detail === 'object') {
        const incoming: MessageItem = {
          sender: detail.sender || 'Unknown',
          text: detail.text || '',
          timestamp: detail.timestamp || new Date().toISOString(),
        };
        setStreamedMessages(prev => [...prev, incoming]);
      }
    };
    target.addEventListener('ggui:agent-data', handler);
    return () => target.removeEventListener('ggui:agent-data', handler);
  }, []);

  const handleSend = () => {
    const trimmed = inputText.trim();
    if (!trimmed) return;
    const payload = { text: trimmed, timestamp: new Date().toISOString() };
    if (rootRef.current) {
      rootRef.current.dispatchEvent(new CustomEvent('ggui:action', { detail: { action: 'sendMessage', payload }, bubbles: true }));
    }
    setStreamedMessages(prev => [...prev, { sender: currentUser, text: trimmed, timestamp: payload.timestamp }]);
    setInputText('');
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend(); }
  };

  const isSendDisabled = inputText.trim().length === 0;

  return (
    <Container maxWidth="md" padding={0}>
      <MotionKeyframes />
      <div ref={rootRef}>
        <Card padding={0} shadow="md" border>
          <div style={{ display: 'flex', flexDirection: 'column', height: '600px', overflow: 'hidden', borderRadius: 'var(--ggui-shape-radius-lg, 12px)' }}>

            {/* HEADER */}
            <div style={{ padding: 'var(--ggui-spacing-4, 16px)', background: 'var(--ggui-color-primary-50, #f0f9ff)', borderBottom: '2px solid var(--ggui-color-primary-200, #bae6fd)', flexShrink: 0 }}>
              <Row align="center" justify="between" gap={8}>
                <Text variant="h3" color="var(--ggui-color-primary-900, #0c4a6e)">{title}</Text>
                {participantCount !== undefined && (
                  <Badge variant="primary" size="sm" pill>{participantCount} participants</Badge>
                )}
              </Row>
            </div>

            {/* MESSAGE LIST */}
            <div role="log" aria-live="polite" aria-label="Chat messages" style={{ flex: 1, overflowY: 'auto', padding: 'var(--ggui-spacing-4, 16px)', background: 'var(--ggui-color-surface, #fafafa)', display: 'flex', flexDirection: 'column', gap: 'var(--ggui-spacing-1, 4px)' }}>
              {allMessages.map((msg, idx) => {
                const isOwn = msg.sender === currentUser;
                const isFirstInGroup = idx === 0 || allMessages[idx - 1]?.sender !== msg.sender;
                const isLastInGroup = idx === allMessages.length - 1 || allMessages[idx + 1]?.sender !== msg.sender;
                const ownRadius = isFirstInGroup && isLastInGroup
                  ? 'var(--ggui-shape-radius-lg, 12px)'
                  : isFirstInGroup
                    ? 'var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-sm, 4px) var(--ggui-shape-radius-lg, 12px)'
                    : isLastInGroup
                      ? 'var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-sm, 4px) var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-lg, 12px)'
                      : 'var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-sm, 4px) var(--ggui-shape-radius-sm, 4px) var(--ggui-shape-radius-lg, 12px)';
                const otherRadius = isFirstInGroup && isLastInGroup
                  ? 'var(--ggui-shape-radius-lg, 12px)'
                  : isFirstInGroup
                    ? 'var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-sm, 4px)'
                    : isLastInGroup
                      ? 'var(--ggui-shape-radius-sm, 4px) var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-lg, 12px)'
                      : 'var(--ggui-shape-radius-sm, 4px) var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-lg, 12px) var(--ggui-shape-radius-sm, 4px)';
                return (
                  <div key={`msg-${idx}-${msg.timestamp ?? ''}`} style={{ display: 'flex', flexDirection: 'column', alignItems: isOwn ? 'flex-end' : 'flex-start', marginTop: isFirstInGroup ? 'var(--ggui-spacing-2, 8px)' : '2px', animation: motionEnabled && idx >= messages.length ? animation.fadeIn : 'none' }}>
                    {isFirstInGroup && !isOwn && (
                      <Text variant="caption" weight="semibold" color="var(--ggui-color-onSurfaceVariant, #52525b)">{msg.sender || 'Unknown'}</Text>
                    )}
                    <div style={{ maxWidth: '75%', padding: 'var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)', background: isOwn ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)', color: isOwn ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-onSurface, #18181b)', borderRadius: isOwn ? ownRadius : otherRadius, boxShadow: 'var(--ggui-shape-shadow-sm, 0 1px 2px rgba(0,0,0,0.05))', wordBreak: 'break-word' }}>
                      <span style={{ fontSize: 'var(--ggui-font-size-sm, 14px)', lineHeight: 1.5 }}>{msg.text || ''}</span>
                    </div>
                    {isLastInGroup && msg.timestamp && (
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">{formatTimestamp(msg.timestamp)}</Text>
                    )}
                  </div>
                );
              })}
              <div ref={messagesEndRef} aria-hidden="true" />
            </div>

            {/* INPUT AREA */}
            <div style={{ padding: 'var(--ggui-spacing-4, 16px)', borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)', background: 'var(--ggui-color-surface, #fafafa)', flexShrink: 0 }}>
              <Row align="center" gap={8}>
                <div style={{ flex: 1 }} onKeyDown={handleKeyDown}>
                  <Text as="label" htmlFor="chat-compose-input" variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Message</Text>
                  <Input label="Message" placeholder="Type a message..." value={inputText} onChange={setInputText} />
                </div>
                <Button variant="primary" size="md" disabled={isSendDisabled} onClick={handleSend} rightIcon={<Icon name="chevron-right" size={16} />} aria-label="Send message">Send</Button>
              </Row>
            </div>

          </div>
        </Card>
      </div>
    </Container>
  );
}

import { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Box,
  Stack,
  Row,
  Text,
  Badge,
  Spacer,
  MotionKeyframes,
  useMotion,
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface StockItem {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: StockItem[];
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

export default function GeneratedComponent({
  stocks: initialStocks = [
    { symbol: 'AAPL', name: 'Apple Inc.', price: 178.72, change: 2.35, changePercent: 1.33 },
    { symbol: 'GOOGL', name: 'Alphabet Inc.', price: 141.80, change: -0.95, changePercent: -0.67 },
    { symbol: 'MSFT', name: 'Microsoft Corp.', price: 378.91, change: 4.12, changePercent: 1.10 },
    { symbol: 'AMZN', name: 'Amazon.com Inc.', price: 185.07, change: -1.23, changePercent: -0.66 },
    { symbol: 'TSLA', name: 'Tesla Inc.', price: 248.42, change: 7.89, changePercent: 3.28 },
    { symbol: 'NVDA', name: 'NVIDIA Corp.', price: 875.28, change: 12.54, changePercent: 1.45 },
  ],
  lastUpdated: initialLastUpdated,
}: Props) {
  const { motionEnabled } = useMotion();

  const [stocks, setStocks] = useState<StockItem[]>(initialStocks);
  const [lastUpdated, setLastUpdated] = useState<string | undefined>(initialLastUpdated);
  const [connectionStatus, setConnectionStatus] = useState<
    'connecting' | 'connected' | 'disconnected'
  >('connecting');

  // Sync with prop changes
  useEffect(() => {
    setStocks(initialStocks);
  }, [initialStocks]);

  useEffect(() => {
    setLastUpdated(initialLastUpdated);
  }, [initialLastUpdated]);

  // Stream Contract: listen for ggui:agent-data events
  useEffect(() => {
    const handleAgentData = (event: Event) => {
      const customEvent = event as CustomEvent;
      const data = customEvent.detail;

      if (data && data.stocks) {
        setStocks(data.stocks);
      }
      if (data && data.lastUpdated) {
        setLastUpdated(data.lastUpdated);
      }
      setConnectionStatus('connected');
    };

    const connectTimeout = setTimeout(() => {
      setConnectionStatus((prev) => (prev === 'connecting' ? 'connected' : prev));
    }, 2000);

    if (typeof globalThis !== 'undefined' && 'addEventListener' in globalThis) {
      (globalThis as typeof globalThis & EventTarget).addEventListener('ggui:agent-data', handleAgentData);
    }

    return () => {
      if (typeof globalThis !== 'undefined' && 'removeEventListener' in globalThis) {
        (globalThis as typeof globalThis & EventTarget).removeEventListener('ggui:agent-data', handleAgentData);
      }
      clearTimeout(connectTimeout);
    };
  }, []);

  const formattedTime = lastUpdated
    ? new Date(lastUpdated).toLocaleString(undefined, {
        month: 'short',
        day: 'numeric',
        hour: '2-digit',
        minute: '2-digit',
        second: '2-digit',
      })
    : '—';

  const getChangeColor = (change: number | undefined): string => {
    if (change === undefined || change === 0)
      return 'var(--ggui-color-onSurfaceVariant, #52525b)';
    return change > 0
      ? 'var(--ggui-color-success-600, #16a34a)'
      : 'var(--ggui-color-error-600, #dc2626)';
  };

  const getBorderColor = (change: number | undefined): string => {
    if (change === undefined || change === 0)
      return 'var(--ggui-color-outline, #d4d4d8)';
    return change > 0
      ? 'var(--ggui-color-success-500, #22c55e)'
      : 'var(--ggui-color-error-500, #ef4444)';
  };

  const getArrow = (change: number | undefined): string => {
    if (change === undefined || change === 0) return '';
    return change > 0 ? '▲' : '▼';
  };

  const statusBadgeVariant =
    connectionStatus === 'connected'
      ? ('success' as const)
      : connectionStatus === 'connecting'
      ? ('warning' as const)
      : ('error' as const);

  const statusLabel =
    connectionStatus === 'connected'
      ? 'Live'
      : connectionStatus === 'connecting'
      ? 'Connecting…'
      : 'Disconnected';

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="xl" padding={24}>
        <Stack direction="vertical" gap={24}>

          {/* === HEADER === */}
          <Box
            padding="var(--ggui-spacing-6, 24px)"
            background="var(--ggui-color-primary-50, #f0f9ff)"
            borderRadius="var(--ggui-shape-radius-lg, 12px)"
          >
            <Row align="center" justify="between" wrap>
              <Stack direction="vertical" gap={4}>
                <Text
                  variant="h1"
                  color="var(--ggui-color-primary-900, #0c4a6e)"
                >
                  Market Watch
                </Text>
                <Text
                  variant="caption"
                  color="var(--ggui-color-primary-700, #0369a1)"
                >
                  Last Updated: {formattedTime}
                </Text>
              </Stack>
              <Badge variant={statusBadgeVariant} size="sm" pill>
                {statusLabel}
              </Badge>
            </Row>
          </Box>

          {/* === LOADING / CONNECTING STATE === */}
          {connectionStatus === 'connecting' && stocks.length === 0 && (
            <Card padding={48} shadow="none">
              <Stack direction="vertical" align="center" gap={16}>
                <Text
                  variant="h3"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  Connecting to market data…
                </Text>
                <Text
                  variant="body"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  Waiting for live stock feed.
                </Text>
              </Stack>
            </Card>
          )}

          {/* === STOCK CARDS GRID === */}
          {stocks.length > 0 && (
            <div
              role="status"
              aria-live="polite"
              aria-label="Stock prices"
              style={{
                display: 'grid',
                gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
                gap: 'var(--ggui-spacing-4, 16px)',
              }}
            >
              {stocks.map((stock, index) => {
                const changeColor = getChangeColor(stock.change);
                const borderColor = getBorderColor(stock.change);
                const arrow = getArrow(stock.change);
                const isPositive = (stock.change ?? 0) > 0;
                const changeSign = isPositive ? '+' : '';

                return (
                  <div
                    key={stock.symbol ?? index}
                    aria-label={`${stock.symbol ?? 'Stock'}: ${stock.name ?? ''}, price $${(stock.price ?? 0).toFixed(2)}, change ${changeSign}${(stock.change ?? 0).toFixed(2)}`}
                    style={{
                      animation: motionEnabled ? animation.fadeIn : 'none',
                      animationDelay: motionEnabled ? `${index * 60}ms` : '0ms',
                      animationFillMode: 'both',
                    }}
                  >
                    <Card padding={20} shadow="sm" border>
                      <div
                        style={{
                          borderLeft: `4px solid ${borderColor}`,
                          paddingLeft: 'var(--ggui-spacing-4, 16px)',
                          transition: `border-color ${transition.colors}`,
                        }}
                      >
                        <Stack direction="vertical" gap={12}>

                          {/* Ticker symbol + company name */}
                          <Stack direction="vertical" gap={2}>
                            <Text
                              variant="h2"
                              weight="bold"
                              color="var(--ggui-color-onSurface, #18181b)"
                            >
                              {stock.symbol ?? '—'}
                            </Text>
                            <Text
                              variant="caption"
                              color="var(--ggui-color-onSurfaceVariant, #52525b)"
                            >
                              {stock.name ?? 'Unknown Company'}
                            </Text>
                          </Stack>

                          {/* Current price */}
                          <Text
                            variant="h3"
                            weight="semibold"
                            color="var(--ggui-color-onSurface, #18181b)"
                          >
                            ${(stock.price ?? 0).toFixed(2)}
                          </Text>

                          {/* Change amount + change percent with arrow */}
                          <Row align="center" gap={12}>
                            <Text
                              variant="body"
                              weight="semibold"
                              color={changeColor}
                            >
                              {changeSign}{(stock.change ?? 0).toFixed(2)}
                            </Text>
                            <Text
                              variant="body"
                              weight="semibold"
                              color={changeColor}
                            >
                              {arrow} {changeSign}{(stock.changePercent ?? 0).toFixed(2)}%
                            </Text>
                          </Row>

                        </Stack>
                      </div>
                    </Card>
                  </div>
                );
              })}
            </div>
          )}

          {/* === EMPTY STATE (after connected but no stocks) === */}
          {connectionStatus !== 'connecting' && stocks.length === 0 && (
            <Card padding={48} shadow="none">
              <Stack direction="vertical" align="center" gap={12}>
                <Text
                  variant="h3"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  No stocks to display
                </Text>
                <Text
                  variant="body"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                >
                  Waiting for market data…
                </Text>
              </Stack>
            </Card>
          )}

        </Stack>
      </Container>
    </>
  );
}

import { useState, useMemo } from 'react';
import {
  Container, Card, Stack, Row, Text, Input, Select, Checkbox, Button,
  Divider, Spacer, Box, Icon, Badge, MotionKeyframes, useMotion
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: {
    name?: string;
    email?: string;
    avatar?: string;
    role?: string;
    emailNotifications?: boolean;
    theme?: string;
  };
  complete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
  onComplete?: (data: {
    name: string;
    email: string;
    avatar: string;
    role: string;
    emailNotifications: boolean;
    theme: string;
  }) => void;
}

const STEP_LABELS = ['Profile Setup', 'Preferences', 'Review & Confirm'];

export default function GeneratedComponent(props: Props) {
  const { initialProfile, avatarOptions, roleOptions, complete, onComplete } = props;
  const fireComplete = complete ?? onComplete ?? (() => undefined);
  const { motionEnabled } = useMotion();

  const [step, setStep] = useState(0);
  const [name, setName] = useState(initialProfile?.name ?? '');
  const [email, setEmail] = useState(initialProfile?.email ?? '');
  const [avatar, setAvatar] = useState(initialProfile?.avatar ?? '');
  const [role, setRole] = useState(initialProfile?.role ?? '');
  const [emailNotifications, setEmailNotifications] = useState(initialProfile?.emailNotifications ?? true);
  const [theme, setTheme] = useState(initialProfile?.theme ?? 'light');
  const [touched, setTouched] = useState<Record<string, boolean>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);

  const emailRegex = /^[^@\s]+@[^@\s]+\.[^@\s]+$/;
  const nameError = touched.name && !name.trim() ? 'Name is required' : '';
  const emailError = touched.email
    ? !email.trim() ? 'Email is required' : !emailRegex.test(email) ? 'Please enter a valid email' : ''
    : '';
  const step1Valid = name.trim() !== '' && emailRegex.test(email);
  const canProceed = useMemo(() => step === 0 ? step1Valid : true, [step, step1Valid]);

  const markTouched = (...fields: string[]) => {
    setTouched(prev => { const n = { ...prev }; fields.forEach(f => { n[f] = true; }); return n; });
  };

  const handleNameChange = (value: string) => { setName(value); if (!touched.name) markTouched('name'); };
  const handleEmailChange = (value: string) => { setEmail(value); if (!touched.email) markTouched('email'); };

  const handleNext = () => {
    if (step === 0) { markTouched('name', 'email'); if (!step1Valid) return; }
    if (step < 2) setStep(s => s + 1);
  };

  const handleBack = () => { if (step > 0) setStep(s => s - 1); };

  const handleSubmitComplete = async () => {
    setIsSubmitting(true);
    try {
      await fireComplete({ name: name.trim(), email: email.trim(), avatar, role, emailNotifications, theme });
    } finally {
      setIsSubmitting(false);
    }
  };

  const handleStepClick = (targetStep: number) => { if (targetStep < step) setStep(targetStep); };
  const roleSelectOptions = roleOptions.map(r => ({ value: r, label: r }));
  const progressPercent = ((step + 1) / 3) * 100;

  const StepIndicator = () => (
    <Stack direction="vertical" gap={8} align="center">
      <Row gap={0} align="center" justify="center">
        {STEP_LABELS.map((label, i) => {
          const isCompleted = i < step;
          const isActive = i === step;
          const isClickable = i < step;
          return (
            <Row key={label} gap={0} align="center">
              {i > 0 && (
                <div style={{
                  width: 48, height: 2,
                  backgroundColor: i <= step ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-outline, #d4d4d8)',
                  transition: motionEnabled ? 'background-color 300ms cubic-bezier(0.4,0,0.2,1)' : 'none',
                }} />
              )}
              <Stack direction="vertical" align="center" gap={4}>
                <div
                  onClick={isClickable ? () => handleStepClick(i) : undefined}
                  role="button"
                  aria-label={`Step ${i + 1} of 3: ${label}`}
                  aria-current={isActive ? 'step' : undefined}
                  tabIndex={isClickable ? 0 : -1}
                  onKeyDown={isClickable ? (e) => { if (e.key === 'Enter' || e.key === ' ') handleStepClick(i); } : undefined}
                  style={{
                    width: 36, height: 36,
                    borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                    fontWeight: 'var(--ggui-font-weight-semibold, 600)' as unknown as number,
                    fontSize: 'var(--ggui-font-size-sm, 14px)',
                    cursor: isClickable ? 'pointer' : 'default',
                    backgroundColor: isCompleted || isActive ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                    color: isCompleted || isActive ? 'var(--ggui-color-surface, #fafafa)' : 'var(--ggui-color-onSurfaceVariant, #52525b)',
                    border: isActive ? '2px solid var(--ggui-color-primary-700, #0369a1)' : '2px solid transparent',
                    transition: motionEnabled ? 'background-color 200ms, color 200ms, border-color 200ms' : 'none',
                    outline: 'none', userSelect: 'none',
                  }}
                >
                  {isCompleted ? <Icon name="check" size={18} color="var(--ggui-color-surface, #fafafa)" /> : i + 1}
                </div>
                <Text
                  variant="caption"
                  color={isActive ? 'var(--ggui-color-primary-700, #0369a1)' : 'var(--ggui-color-onSurfaceVariant, #52525b)'}
                  weight={isActive ? 'semibold' : 'normal'}
                >
                  {label}
                </Text>
              </Stack>
            </Row>
          );
        })}
      </Row>
      <div
        role="progressbar"
        aria-valuenow={step + 1}
        aria-valuemin={1}
        aria-valuemax={3}
        aria-label={`Step ${step + 1} of 3`}
        style={{
          width: '100%', height: 4,
          backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
          borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
          overflow: 'hidden',
        }}
      >
        <div style={{
          height: '100%', width: `${progressPercent}%`,
          backgroundColor: 'var(--ggui-color-primary-600, #0284c7)',
          borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
          transition: motionEnabled ? 'width 300ms cubic-bezier(0.4,0,0.2,1)' : 'none',
        }} />
      </div>
    </Stack>
  );

  const Step1 = () => (
    <Stack direction="vertical" gap={16}>
      <Stack direction="vertical" gap={4}>
        <Text variant="h3">Profile Setup</Text>
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Tell us about yourself</Text>
      </Stack>
      <Input label="Name" placeholder="Enter your full name" value={name} onChange={handleNameChange} required error={nameError} />
      <Input label="Email" type="email" placeholder="you@example.com" value={email} onChange={handleEmailChange} required error={emailError} />
      <Stack direction="vertical" gap={8}>
        <Text variant="label">Choose your avatar</Text>
        <div role="radiogroup" aria-label="Avatar selection" style={{ display: 'flex', gap: 12, flexWrap: 'wrap', justifyContent: 'center' }}>
          {avatarOptions.map((emoji) => (
            <div
              key={emoji}
              role="radio"
              aria-checked={avatar === emoji}
              aria-label={`Avatar ${emoji}`}
              tabIndex={0}
              onClick={() => setAvatar(emoji)}
              onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); setAvatar(emoji); } }}
              style={{
                width: 56, height: 56,
                borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                fontSize: 24, cursor: 'pointer',
                backgroundColor: avatar === emoji ? 'var(--ggui-color-primary-100, #e0f2fe)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                border: avatar === emoji ? '2px solid var(--ggui-color-primary-600, #0284c7)' : '2px solid var(--ggui-color-outline, #d4d4d8)',
                transform: avatar === emoji ? 'scale(1.1)' : 'scale(1)',
                transition: motionEnabled ? 'background-color 200ms, border-color 200ms, transform 200ms' : 'none',
                outline: 'none', userSelect: 'none',
              }}
            >
              {emoji}
            </div>
          ))}
        </div>
      </Stack>
    </Stack>
  );

  const Step2 = () => (
    <Stack direction="vertical" gap={16}>
      <Stack direction="vertical" gap={4}>
        <Text variant="h3">Preferences</Text>
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Customize your experience</Text>
      </Stack>
      <Select label="Role" value={role} onChange={setRole} options={roleSelectOptions} placeholder="Select your role" />
      <Checkbox label="Email Notifications" checked={emailNotifications} onChange={setEmailNotifications} description="Receive updates and announcements via email" />
      <Stack direction="vertical" gap={8}>
        <Text variant="label">Theme Preference</Text>
        <div role="radiogroup" aria-label="Theme preference" style={{ display: 'flex', gap: 12 }}>
          {[{ value: 'light', label: '☀️ Light' }, { value: 'dark', label: '🌙 Dark' }].map((option) => (
            <div
              key={option.value}
              role="radio"
              aria-checked={theme === option.value}
              aria-label={`${option.label} theme`}
              tabIndex={0}
              onClick={() => setTheme(option.value)}
              onKeyDown={(e) => { if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); setTheme(option.value); } }}
              style={{
                flex: 1,
                padding: 'var(--ggui-spacing-4, 16px)',
                borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                textAlign: 'center' as const,
                cursor: 'pointer',
                fontWeight: 'var(--ggui-font-weight-medium, 500)' as unknown as number,
                fontSize: 'var(--ggui-font-size-sm, 14px)',
                backgroundColor: theme === option.value ? 'var(--ggui-color-primary-50, #f0f9ff)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                border: theme === option.value ? '2px solid var(--ggui-color-primary-600, #0284c7)' : '2px solid var(--ggui-color-outline, #d4d4d8)',
                color: theme === option.value ? 'var(--ggui-color-primary-700, #0369a1)' : 'var(--ggui-color-onSurfaceVariant, #52525b)',
                transition: motionEnabled ? 'background-color 200ms, border-color 200ms, color 200ms' : 'none',
                outline: 'none', userSelect: 'none',
              }}
            >
              {option.label}
            </div>
          ))}
        </div>
      </Stack>
    </Stack>
  );

  const Step3 = () => (
    <Stack direction="vertical" gap={16}>
      <Stack direction="vertical" gap={4}>
        <Text variant="h3">Review &amp; Confirm</Text>
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Please review your selections before completing setup</Text>
      </Stack>
      <Box background="var(--ggui-color-surfaceVariant, #f4f4f5)" padding={20} borderRadius="var(--ggui-shape-radius-lg, 12px)">
        <Stack direction="vertical" gap={12}>
          <Text variant="caption" color="var(--ggui-color-primary-600, #0284c7)" weight="semibold">PROFILE</Text>
          <Row justify="between" align="center">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Name</Text>
            <Text variant="body" weight="medium">{avatar ? `${avatar} ` : ''}{name}</Text>
          </Row>
          <Row justify="between" align="center">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Email</Text>
            <Text variant="body" weight="medium">{email}</Text>
          </Row>
          <Divider margin={4} />
          <Text variant="caption" color="var(--ggui-color-primary-600, #0284c7)" weight="semibold">PREFERENCES</Text>
          <Row justify="between" align="center">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Role</Text>
            <Text variant="body" weight="medium">{role || '—'}</Text>
          </Row>
          <Row justify="between" align="center">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Notifications</Text>
            <Badge variant={emailNotifications ? 'success' : 'default'} size="sm">
              {emailNotifications ? 'On' : 'Off'}
            </Badge>
          </Row>
          <Row justify="between" align="center">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Theme</Text>
            <Text variant="body" weight="medium">{theme === 'light' ? '☀️ Light' : '🌙 Dark'}</Text>
          </Row>
        </Stack>
      </Box>
      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)" align="center">
        You can always change these settings later.
      </Text>
    </Stack>
  );

  return (
    <>
      <MotionKeyframes />
      <Container maxWidth="sm">
        <Card padding={32} shadow="md">
          <Stack direction="vertical" gap={24}>
            <Text variant="h2" align="center" color="var(--ggui-color-onSurface, #18181b)">
              Welcome! Let&apos;s get set up
            </Text>
            <StepIndicator />
            <Divider margin={4} />
            <div key={step} aria-live="polite" style={{ animation: motionEnabled ? animation.fadeIn : 'none' }}>
              {step === 0 && <Step1 />}
              {step === 1 && <Step2 />}
              {step === 2 && <Step3 />}
            </div>
            <Divider margin={4} />
            <Row justify="between" align="center">
              {step > 0 ? (
                <Button variant="outline" onClick={handleBack} leftIcon={<Icon name="chevron-left" size={16} />} aria-label="Go to previous step">
                  {step === 2 ? 'Go Back' : 'Back'}
                </Button>
              ) : (
                <Spacer size={1} />
              )}
              {step < 2 ? (
                <Button variant="primary" onClick={handleNext} disabled={!canProceed} rightIcon={<Icon name="chevron-right" size={16} />} aria-label="Go to next step">
                  Next
                </Button>
              ) : (
                <Button variant="primary" onClick={handleSubmitComplete} loading={isSubmitting} disabled={isSubmitting} leftIcon={<Icon name="check" size={16} />}>
                  Complete Setup
                </Button>
              )}
            </Row>
          </Stack>
        </Card>
      </Container>
    </>
  );
}

import React from 'react';
import { 
  Card, 
  Stack, 
  Row, 
  Text, 
  Divider, 
  Box, 
  MotionKeyframes, 
  useMotion 
} from '@ggui-ai/design/primitives';
import { animation } from '@ggui-ai/design/tokens';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * Helper to map weather condition strings to emojis
 */
const getConditionEmoji = (condition: string): string => {
  const c = (condition || '').toLowerCase();
  if (c.includes('sun') || c.includes('clear')) return '☀️';
  if (c.includes('cloud')) return '☁️';
  if (c.includes('rain') || c.includes('drizzle')) return '🌧️';
  if (c.includes('storm') || c.includes('thunder')) return '⛈️';
  if (c.includes('snow')) return '❄️';
  if (c.includes('mist') || c.includes('fog')) return '🌫️';
  return '🌡️';
};

export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast = []
}: Props) {
  const { motionEnabled } = useMotion();

  return (
    <Box padding="var(--ggui-spacing-4)">
      <MotionKeyframes />
      <Card 
        shadow="md" 
        padding="var(--ggui-spacing-6)"
        style={{
          maxWidth: '400px',
          margin: '0 auto',
          background: 'var(--ggui-color-surface)',
          animation: motionEnabled ? animation.fadeIn : 'none',
        }}
      >
        <Stack gap={24} align="stretch">
          {/* Header Section */}
          <Stack gap={4} align="center">
            <Text variant="h2" weight="bold" color="var(--ggui-color-onSurface)">
              {city}
            </Text>
            <Row gap={8} align="center">
              <Text style={{ fontSize: 'var(--ggui-font-size-xl)' }}>
                {getConditionEmoji(condition)}
              </Text>
              <Text 
                variant="body" 
                color="var(--ggui-color-onSurfaceVariant)"
                weight="medium"
              >
                {condition}
              </Text>
            </Row>
          </Stack>

          {/* Main Temperature */}
          <Stack align="center" gap={0}>
            <Row align="start" justify="center">
              <Text 
                weight="bold" 
                style={{ 
                  fontSize: 'var(--ggui-font-size-4xl)', 
                  color: 'var(--ggui-color-primary-600)',
                  lineHeight: 1
                }}
              >
                {Math.round(temperature)}
              </Text>
              <Text 
                variant="h3" 
                weight="semibold" 
                color="var(--ggui-color-primary-500)"
                style={{ marginTop: 'var(--ggui-spacing-1)' }}
              >
                °{unit}
              </Text>
            </Row>
          </Stack>

          {/* Stats Bar */}
          <Row 
            justify="around" 
            padding="var(--ggui-spacing-4)"
            style={{ 
              backgroundColor: 'var(--ggui-color-surfaceVariant)', 
              borderRadius: 'var(--ggui-shape-radius-lg)',
              border: '1px solid var(--ggui-color-outlineVariant)'
            }}
          >
            <Stack align="center" gap={4}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" weight="medium">
                HUMIDITY
              </Text>
              <Text weight="bold" color="var(--ggui-color-onSurface)">
                {humidity}%
              </Text>
            </Stack>
            <Divider orientation="vertical" margin={0} />
            <Stack align="center" gap={4}>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)" weight="medium">
                WIND
              </Text>
              <Text weight="bold" color="var(--ggui-color-onSurface)">
                {windSpeed} km/h
              </Text>
            </Stack>
          </Row>

          <Divider margin={0} />

          {/* Forecast Strip */}
          <Row justify="between" align="center" gap={8} wrap>
            {forecast.slice(0, 5).map((item, index) => (
              <Box 
                key={item.day || index}
                padding="var(--ggui-spacing-2)"
                style={{ 
                  flex: '1 1 0px',
                  minWidth: '60px',
                  animation: motionEnabled ? animation.slideInUp : 'none',
                  animationDelay: `${index * 50}ms`,
                  animationFillMode: 'both'
                }}
              >
                <Stack align="center" gap={4}>
                  <Text variant="caption" weight="semibold" color="var(--ggui-color-onSurfaceVariant)">
                    {item.day?.substring(0, 3).toUpperCase() || '---'}
                  </Text>
                  <Text style={{ fontSize: 'var(--ggui-font-size-xl)' }}>
                    {item.icon || '☀️'}
                  </Text>
                  <Stack gap={0} align="center">
                    <Text weight="bold" style={{ fontSize: 'var(--ggui-font-size-sm)' }}>
                      {Math.round(item.high || 0)}°
                    </Text>
                    <Text 
                      color="var(--ggui-color-onSurfaceVariant)" 
                      style={{ fontSize: 'var(--ggui-font-size-xs)' }}
                    >
                      {Math.round(item.low || 0)}°
                    </Text>
                  </Stack>
                </Stack>
              </Box>
            ))}
          </Row>
        </Stack>
      </Card>
    </Box>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  TextArea,
  Button,
  Checkbox,
  RadioGroup,
  Divider,
  Icon,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface FormData {
  name: string;
  email: string;
  satisfaction: string;
  features: string[];
  comments: string;
}

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Called when the survey is submitted */
  onSubmit: (data: FormData) => void;
}

/**
 * MultiStepSurvey - A robust multi-step survey with progress tracking and validation.
 */
export default function MultiStepSurvey({
  featureOptions = ['Cloud Sync', 'Dark Mode', 'API Integration', 'Mobile App', 'Team Billing'],
  satisfactionLabels = ['Poor', 'Fair', 'Good', 'Very Good', 'Excellent'],
  onSubmit
}: Props) {
  const [step, setStep] = useState(0);
  const [isSubmitting, setIsSubmitting] = useState(false);
  const { motionEnabled } = useMotion();

  const [formData, setFormData] = useState<FormData>({
    name: '',
    email: '',
    satisfaction: '',
    features: [],
    comments: '',
  });

  const [errors, setErrors] = useState<Record<string, string>>({});

  const validateEmail = (email: string) => {
    if (!email) return 'Email is required';
    if (!/^[^@]+@[^@]+\.[^@]+$/.test(email)) return 'Invalid email format';
    return '';
  };

  const updateField = (field: keyof FormData, value: any) => {
    setFormData((prev) => ({ ...prev, [field]: value }));
    if (errors[field]) {
      setErrors((prev) => {
        const nextErrors = { ...prev };
        delete nextErrors[field];
        return nextErrors;
      });
    }
  };

  const isStepValid = () => {
    if (step === 0) {
      return formData.name.trim() !== '' && /^[^@]+@[^@]+\.[^@]+$/.test(formData.email);
    }
    if (step === 1) return formData.satisfaction !== '';
    return true;
  };

  const handleNext = () => {
    if (step === 0) {
      const emailErr = validateEmail(formData.email);
      const nameErr = formData.name.trim() ? '' : 'Name is required';
      if (emailErr || nameErr) {
        setErrors({ email: emailErr, name: nameErr });
        return;
      }
    }
    setStep((s) => s + 1);
  };

  const handleBack = () => {
    if (step > 0) setStep((s) => s - 1);
  };

  const handleSubmit = async () => {
    setIsSubmitting(true);
    try {
      if (onSubmit) {
        await onSubmit(formData);
      }
    } catch (err) {
      console.error('Survey error:', err);
    } finally {
      setIsSubmitting(false);
    }
  };

  const toggleFeature = (feature: string) => {
    setFormData((prev) => {
      const features = prev.features.includes(feature)
        ? prev.features.filter((f) => f !== feature)
        : [...prev.features, feature];
      return { ...prev, features };
    });
  };

  const satisfactionOptions = useMemo(() => 
    satisfactionLabels.slice(0, 5).map((label, index) => ({
      value: String(index + 1),
      label: `${index + 1} - ${label}`
    })), [satisfactionLabels]);

  const steps = ['Introduction', 'Experience', 'Features', 'Comments', 'Review'];
  const progressPercent = ((step + 1) / steps.length) * 100;

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-8, 32px)">
      <MotionKeyframes />
      <Stack gap={32}>
        {/* Progress Display */}
        <Stack gap={12}>
          <Row justify="between" align="end">
            <Stack gap={4}>
              <Text variant="caption" weight="bold" color="var(--ggui-color-primary-600)">STEP {step + 1} OF {steps.length}</Text>
              <Text variant="h3">{steps[step]}</Text>
            </Stack>
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{Math.round(progressPercent)}% complete</Text>
          </Row>
          <div style={{ height: 8, width: '100%', backgroundColor: 'var(--ggui-color-outlineVariant)', borderRadius: 999 }}>
            <div style={{
              height: '100%',
              width: `${progressPercent}%`,
              backgroundColor: 'var(--ggui-color-primary-600)',
              transition: motionEnabled ? `width ${transition.normal}` : 'none',
              borderRadius: 999
            }} />
          </div>
        </Stack>

        <Card padding={32} shadow="md" border>
          <Stack gap={32}>
            <div style={{ minHeight: 320, animation: motionEnabled ? animation.fadeIn : 'none' }} key={step}>

              {step === 0 && (
                <Stack gap={24}>
                  <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">Please tell us who you are.</Text>
                  <Stack gap={8}>
                    <Text variant="label" as="label" htmlFor="name-input">Full Name</Text>
                    <Input label="Full Name" id="name-input" value={formData.name} onChange={(v) => updateField('name', v)} required error={errors.name} placeholder="Enter your full name" />
                  </Stack>
                  <Stack gap={8}>
                    <Text variant="label" as="label" htmlFor="email-input">Email Address</Text>
                    <Input label="Email Address" id="email-input" type="email" value={formData.email} onChange={(v) => updateField('email', v)} required error={errors.email} placeholder="Enter your email address" />
                  </Stack>
                </Stack>
              )}

              {step === 1 && (
                <Stack gap={24}>
                  <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">How would you rate your overall experience?</Text>
                  <RadioGroup label="Rating Selection" value={formData.satisfaction} onChange={(v) => updateField('satisfaction', v)} options={satisfactionOptions} />
                </Stack>
              )}

              {step === 2 && (
                <Stack gap={24}>
                  <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">Select features that you find most valuable.</Text>
                  <Stack gap={12}>
                    {featureOptions.map((option) => (
                      <Card key={option} padding={16} border style={{ backgroundColor: formData.features.includes(option) ? 'var(--ggui-color-primary-50)' : 'transparent' }}>
                        <Checkbox label={option} checked={formData.features.includes(option)} onChange={() => toggleFeature(option)} />
                      </Card>
                    ))}
                  </Stack>
                </Stack>
              )}

              {step === 3 && (
                <Stack gap={24}>
                  <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">Any other feedback you'd like to share?</Text>
                  <Stack gap={8}>
                    <TextArea label="Feedback Message" placeholder="Optional comments..." value={formData.comments} onChange={(v) => updateField('comments', v)} maxLength={500} rows={5} />
                    <Row justify="end">
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{formData.comments.length} / 500 characters</Text>
                    </Row>
                  </Stack>
                </Stack>
              )}

              {step === 4 && (
                <Stack gap={24}>
                  <Text variant="h3">Final Review</Text>
                  <Stack gap={16} style={{ padding: 24, backgroundColor: 'var(--ggui-color-surfaceVariant)', borderRadius: 'var(--ggui-shape-radius-lg)' }}>
                    <Row justify="between"><Text weight="semibold">Name</Text><Text>{formData.name}</Text></Row>
                    <Divider margin={4} />
                    <Row justify="between"><Text weight="semibold">Email</Text><Text>{formData.email}</Text></Row>
                    <Divider margin={4} />
                    <Row justify="between"><Text weight="semibold">Satisfaction</Text><Text>{satisfactionLabels[parseInt(formData.satisfaction) - 1] || 'N/A'}</Text></Row>
                    <Divider margin={4} />
                    <Stack gap={4}>
                      <Text weight="semibold">Interested Features</Text>
                      <Text variant="caption">{formData.features.length > 0 ? formData.features.join(', ') : 'None'}</Text>
                    </Stack>
                    <Divider margin={4} />
                    <Stack gap={4}>
                      <Text weight="semibold">Comments</Text>
                      <Text variant="caption">{formData.comments || 'No comments'}</Text>
                    </Stack>
                  </Stack>
                </Stack>
              )}
            </div>

            <Divider />

            <Row justify="between">
              <Button variant="outline" onClick={handleBack} disabled={step === 0 || isSubmitting} leftIcon={<Icon name="chevron-left" size={18} />}>Back</Button>
              {step < steps.length - 1 ? (
                <Button variant="primary" onClick={handleNext} disabled={!isStepValid()} rightIcon={<Icon name="chevron-right" size={18} />}>Next</Button>
              ) : (
                <Button variant="primary" onClick={handleSubmit} loading={isSubmitting} disabled={isSubmitting} leftIcon={<Icon name="check" size={18} />}>Submit Survey</Button>
              )}
            </Row>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Box,
  Badge,
  Icon,
  Divider,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Props {
  elements: Array<{
    atomicNumber?: number;
    symbol?: string;
    name?: string;
    atomicWeight?: number;
    category?: string;
    row?: number;
    col?: number;
  }>;
}

const getCategoryColor = (cat: string = ''): string => {
  const c = cat.toLowerCase();
  if (c.includes('alkali')) return 'var(--ggui-color-error-500, #ef4444)';
  if (c.includes('alkaline')) return 'var(--ggui-color-warning-500, #f59e0b)';
  if (c.includes('transition')) return 'var(--ggui-color-primary-300, #7dd3fc)';
  if (c.includes('noble')) return 'var(--ggui-color-neutral-700, #374151)';
  return 'var(--ggui-color-primary-500, #0ea5e9)';
};

export default function PeriodicTable({ elements = [] }: Props) {
  const [searchTerm, setSearchTerm] = useState('');
  const [selected, setSelected] = useState<Props['elements'][0] | null>(null);
  const { motionEnabled } = useMotion();

  const cats = useMemo(() => Array.from(new Set(elements.map(e => e.category).filter(Boolean))).sort(), [elements]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Stack gap={24}>
        <Card padding="var(--ggui-spacing-6, 24px)">
          <Stack gap={16}>
            <Text variant="h1">Periodic Table</Text>
            <Input label="Search Elements" value={searchTerm} onChange={setSearchTerm} placeholder="Filter by name or symbol" />
          </Stack>
        </Card>

        <Card padding="var(--ggui-spacing-4, 16px)">
          <Row gap={12} wrap>
            {cats.map(c => (
              <Row key={c || ''} gap={4} align="center">
                <Box style={{ width: 12, height: 12, borderRadius: 'var(--ggui-shape-radius-sm, 4px)', backgroundColor: getCategoryColor(c || '') }} />
                <Text variant="caption">{c}</Text>
              </Row>
            ))}
          </Row>
        </Card>

        <Box style={{ overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-4, 16px)' }}>
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(18, var(--ggui-spacing-12, 48px))', gap: 'var(--ggui-spacing-1, 4px)', minWidth: '940px' }}>
            {elements.map(e => {
              const m = !searchTerm || e.name?.toLowerCase().includes(searchTerm.toLowerCase()) || e.symbol?.toLowerCase().includes(searchTerm.toLowerCase());
              const sel = selected?.atomicNumber === e.atomicNumber;
              const col = getCategoryColor(e.category);
              return (
                <div key={e.atomicNumber} onClick={() => setSelected(e)} style={{ gridRow: e.row, gridColumn: e.col, cursor: 'pointer', opacity: m ? 1 : 0.2, transform: sel ? 'scale(1.1)' : 'scale(1)', transition: transition.normal, zIndex: sel ? 10 : 1 }}>
                  <Card padding={4} style={{ height: 'var(--ggui-spacing-12, 48px)', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', backgroundColor: sel ? 'var(--ggui-color-surface)' : 'var(--ggui-color-surfaceVariant)', border: sel ? `2px solid ${col}` : '1px solid var(--ggui-color-outline)' }}>
                    <Text variant="caption" style={{ fontSize: '8px', lineHeight: 1 }}>{e.atomicNumber}</Text>
                    <Text variant="body" weight="bold" style={{ color: col, lineHeight: 1 }}>{e.symbol}</Text>
                  </Card>
                </div>
              );
            })}
          </div>
        </Box>

        {selected && (
          <Card padding="var(--ggui-spacing-8, 32px)" style={{ animation: motionEnabled ? animation.slideInUp : 'none', borderLeft: `var(--ggui-spacing-2, 8px) solid ${getCategoryColor(selected.category)}` }}>
            <Stack direction="horizontal" gap={32} align="center" wrap>
              <Box style={{ width: 120, height: 120, display: 'flex', alignItems: 'center', justifyContent: 'center', borderRadius: 'var(--ggui-shape-radius-lg, 12px)', backgroundColor: 'var(--ggui-color-surfaceVariant)', border: `3px solid ${getCategoryColor(selected.category)}` }}>
                <Stack align="center" gap={0}>
                  <Text weight="bold">{selected.atomicNumber}</Text>
                  <Text style={{ fontSize: '48px', fontWeight: 'bold', color: getCategoryColor(selected.category) }}>{selected.symbol}</Text>
                </Stack>
              </Box>
              <Stack gap={16} style={{ flex: 1, minWidth: '300px' }}>
                <Row justify="between" align="center"><Text variant="h2">{selected.name}</Text><Badge variant="info">{selected.category}</Badge></Row>
                <Divider />
                <Row gap={24} wrap>
                  <Stack gap={4}><Text variant="caption">WEIGHT</Text><Text weight="bold">{selected.atomicWeight}</Text></Stack>
                  <Stack gap={4}><Text variant="caption">PERIOD</Text><Text weight="bold">{selected.row}</Text></Stack>
                  <Stack gap={4}><Text variant="caption">GROUP</Text><Text weight="bold">{selected.col}</Text></Stack>
                </Row>
              </Stack>
            </Stack>
          </Card>
        )}
      </Stack>
    </Container>
  );
}

import React, { useState, useEffect, useRef } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Button,
  Badge,
  Icon,
  Box,
  Divider,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Message {
  sender?: string;
  text?: string;
  timestamp?: string;
}

interface Props {
  title: string;
  currentUser: string;
  participantCount?: number;
  messages: Array<Message>;
  sendMessage: (payload: { text: string; timestamp: string }) => void;
}

export default function ChatInterface(props: Props) {
  const { title, currentUser, participantCount, messages, sendMessage } = props;
  const [inputValue, setInputValue] = useState('');
  const [localMessages, setLocalMessages] = useState<Message[]>(messages);
  const scrollRef = useRef<HTMLDivElement>(null);
  const { motionEnabled } = useMotion();

  useEffect(() => {
    setLocalMessages(messages);
  }, [messages]);

  useEffect(() => {
    const handleData = (e: any) => {
      const data = e.detail;
      if (data && (data.text || data.message)) {
        setLocalMessages(prev => [...prev, {
          sender: data.sender || 'Assistant',
          text: data.text || data.message,
          timestamp: new Date().toISOString()
        }]);
      }
    };
    addEventListener('ggui:agent-data', handleData as EventListener);
    return () => removeEventListener('ggui:agent-data', handleData as EventListener);
  }, []);

  useEffect(() => {
    if (scrollRef.current) scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
  }, [localMessages]);

  const onSend = () => {
    if (!inputValue.trim()) return;
    const p = { text: inputValue, timestamp: new Date().toISOString() };
    setLocalMessages(prev => [...prev, { sender: currentUser, ...p }]);
    sendMessage(p);
    setInputValue('');
  };

  return (
    <Container maxWidth="md" padding={0}>
      <MotionKeyframes />
      <Card padding={0} style={{ display: 'flex', flexDirection: 'column', height: 'var(--ggui-spacing-128, 512px)', backgroundColor: 'var(--ggui-color-surface)' }}>
        <Box padding="16px" style={{ borderBottom: '1px solid var(--ggui-color-outline)' }}>
          <Row justify="between">
            <Stack gap={4}>
              <Text variant="h3">{title}</Text>
              {participantCount && <Badge size="sm">{participantCount} active</Badge>}
            </Stack>
            <Icon name="settings" />
          </Row>
        </Box>
        <Box ref={scrollRef} style={{ flex: 1, overflowY: 'auto' }} padding="16px">
          <Stack gap={8}>
            {localMessages.map((m, i) => (
              <Box key={i} style={{ alignSelf: m.sender === currentUser ? 'flex-end' : 'flex-start', maxWidth: '85%' }}>
                <Box style={{ padding: '8px 16px', backgroundColor: m.sender === currentUser ? 'var(--ggui-color-primary-600)' : 'var(--ggui-color-surfaceVariant)', color: m.sender === currentUser ? 'var(--ggui-color-surface, #ffffff)' : 'inherit', borderRadius: '8px' }}>
                  <Text>{m.text}</Text>
                </Box>
              </Box>
            ))}
          </Stack>
        </Box>
        <Divider margin={0} />
        <Box padding="16px">
          <Text as="label" htmlFor="chat-input">Message</Text>
          <Input label="Message" value={inputValue} onChange={setInputValue} />
          <Button variant="primary" onClick={onSend} disabled={!inputValue}>Send Message</Button>
        </Box>
      </Card>
    </Container>
  );
}

import React, { useState, useEffect } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Icon,
  Box,
  Divider,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Props {
  lastUpdated?: string;
  stocks: Array<{
    symbol?: string;
    name?: string;
    price?: number;
    change?: number;
    changePercent?: number;
  }>;
}

export default function StockTickerDashboard(props: Props) {
  const [stocks, setStocks] = useState(props.stocks || []);
  const [lastUpdated, setLastUpdated] = useState(props.lastUpdated);
  const { motionEnabled } = useMotion();

  useEffect(() => {
    const handleData = (event: any) => {
      const data = event.detail?.data;
      if (data) {
        if (data.stocks) setStocks(data.stocks);
        if (data.lastUpdated) setLastUpdated(data.lastUpdated);
      }
    };

    // Global listener
    if (typeof addEventListener !== 'undefined') {
      addEventListener('ggui:agent-data', handleData);
      return () => removeEventListener('ggui:agent-data', handleData);
    }
  }, []);

  useEffect(() => {
    if (props.stocks) setStocks(props.stocks);
    if (props.lastUpdated) setLastUpdated(props.lastUpdated);
  }, [props.stocks, props.lastUpdated]);

  const formatPrice = (p?: number) => (p ?? 0).toFixed(2);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <MotionKeyframes />
      <Stack gap={24}>
        <Stack gap={4}>
          <Text variant="h1" weight="bold">Market Watch</Text>
          <Text variant="caption" style={{ color: 'var(--ggui-color-onSurfaceVariant)' }}>
            Updated: {lastUpdated || 'Connecting...'}
          </Text>
        </Stack>

        <Divider margin={0} />

        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))',
          gap: 'var(--ggui-spacing-6)'
        }}>
          {stocks.map((item, idx) => {
            const isUp = (item.change || 0) >= 0;
            const color = isUp ? 'var(--ggui-color-success-600)' : 'var(--ggui-color-error-600)';

            return (
              <Card 
                key={`${item.symbol}-${idx}`}
                padding={24}
                style={{
                  border: `1px solid ${color}`,
                  animation: motionEnabled ? animation.fadeIn : 'none',
                  animationDelay: `${idx * 40}ms`,
                  transition: transition.colors
                }}
              >
                <Stack gap={16}>
                  <Row justify="between" align="start">
                    <Stack gap={0}>
                      <Text variant="h3" weight="bold">{item.symbol || '???'}</Text>
                      <Text variant="caption" style={{ color: 'var(--ggui-color-onSurfaceVariant)' }}>
                        {item.name || 'Company Name'}
                      </Text>
                    </Stack>
                    <Icon name={isUp ? 'chevron-up' : 'chevron-down'} color={color} size={20} />
                  </Row>

                  <Stack gap={8}>
                    <Text variant="h2" weight="bold">${formatPrice(item.price)}</Text>
                    <Row gap={8} align="center">
                      <Text weight="semibold" style={{ color }}>
                        {isUp ? '+' : ''}{(item.change || 0).toFixed(2)}
                      </Text>
                      <Box 
                        paddingX={8} 
                        paddingY={4} 
                        borderRadius="var(--ggui-shape-radius-full)"
                        style={{ background: `${color}15` }}
                      >
                        <Text variant="caption" weight="bold" style={{ color }}>
                          {isUp ? '▲' : '▼'} {Math.abs(item.changePercent || 0).toFixed(2)}%
                        </Text>
                      </Box>
                    </Row>
                  </Stack>
                </Stack>
              </Card>
            );
          })}
        </div>
      </Stack>
    </Container>
  );
}

import React from 'react';
import {
  Card,
  Stack,
  Row,
  Text,
  Divider,
  Box,
