interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * WeatherCard Component
 * Displays current weather and a 5-day forecast.
 */
export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast
}: Props) {
  const { motionEnabled } = useMotion();

  // Helper for weather icons (mapping condition strings to emojis or icons)
  const getWeatherEmoji = (cond: string = '') => {
    const c = cond.toLowerCase();
    if (c.includes('sun') || c.includes('clear')) return '☀️';
    if (c.includes('cloud')) return '☁️';
    if (c.includes('rain') || c.includes('drizzle')) return '🌧️';
    if (c.includes('thunder') || c.includes('storm')) return '⛈️';
    if (c.includes('snow')) return '❄️';
    if (c.includes('fog') || c.includes('mist')) return '🌫️';
    return '⛅';
  };

  return (
    <Box padding="var(--ggui-spacing-4, 16px)">
      <MotionKeyframes />
      <Card
        padding={0}
        shadow="lg"
        style={{
          overflow: 'hidden',
          maxWidth: '450px',
          margin: '0 auto',
          background: 'var(--ggui-color-surface, #fafafa)',
          animation: motionEnabled ? animation.scaleIn : 'none',
        }}
      >
        {/* Main Header / Current Weather */}
        <Stack
          gap={0}
          style={{
            background: 'linear-gradient(135deg, var(--ggui-color-primary-600, #0284c7), var(--ggui-color-primary-800, #075985))',
            padding: 'var(--ggui-spacing-8, 32px)',
            color: 'var(--ggui-color-surface, #ffffff)',
          }}
        >
          <Text variant="h2" weight="bold" color="inherit">
            {city}
          </Text>
          <Text 
            variant="body" 
            style={{ 
              color: 'var(--ggui-color-primary-100, #e0f2fe)',
              fontWeight: 'var(--ggui-font-weight-medium, 500)'
            }}
          >
            {condition}
          </Text>

          <Row align="center" justify="between" style={{ marginTop: 'var(--ggui-spacing-4, 16px)' }}>
            <Text
              style={{
                fontSize: 'var(--ggui-font-size-4xl, 36px)',
                lineHeight: 1,
                fontWeight: 'var(--ggui-font-weight-bold, 700)',
                color: 'inherit'
              }}
            >
              {Math.round(temperature)}°{unit}
            </Text>
            <span style={{ fontSize: '4rem' }} role="img" aria-label={condition}>
              {getWeatherEmoji(condition)}
            </span>
          </Row>
        </Stack>

        {/* Detailed Stats */}
        <Stack padding="var(--ggui-spacing-6, 24px)" gap={20}>
          <Row justify="around">
            <Stack align="center" gap={4}>
              <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                HUMIDITY
              </Text>
              <Text weight="semibold" style={{ fontSize: 'var(--ggui-font-size-lg, 18px)' }}>
                {humidity}%
              </Text>
            </Stack>
            <Divider orientation="vertical" margin={0} style={{ height: '32px' }} />
            <Stack align="center" gap={4}>
              <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                WIND
              </Text>
              <Text weight="semibold" style={{ fontSize: 'var(--ggui-font-size-lg, 18px)' }}>
                {windSpeed} km/h
              </Text>
            </Stack>
          </Row>

          <Divider margin={8} />

          {/* 5-Day Forecast Strip */}
          <Text variant="label" weight="semibold">5-Day Forecast</Text>
          <Row gap={12} justify="between" style={{ overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-1, 4px)' }}>
            {forecast.map((item, index) => (
              <Box
                key={`forecast-\${item.day}-\${index}`}
                padding="var(--ggui-spacing-2, 8px)"
                borderRadius="var(--ggui-shape-radius-md, 8px)"
                style={{
                  minWidth: '64px',
                  textAlign: 'center',
                  background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  animation: motionEnabled ? animation.slideInUp : 'none',
                  animationDelay: `\${index * 50}ms`,
                  animationFillMode: 'both'
                }}
              >
                <Stack gap={4} align="center">
                  <Text variant="caption" weight="bold">
                    {item.day}
                  </Text>
                  <span style={{ fontSize: '1.5rem' }} role="img" aria-label="forecast-icon">
                    {item.icon || getWeatherEmoji()}
                  </span>
                  <Stack gap={0} align="center">
                    <Text variant="caption" weight="semibold">
                      {Math.round(item.high || 0)}°
                    </Text>
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                      {Math.round(item.low || 0)}°
                    </Text>
                  </Stack>
                </Stack>
              </Box>
            ))}
          </Row>
        </Stack>
      </Card>
    </Box>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  TextArea,
  Checkbox,
  RadioGroup,
  Button,
  Divider,
  Icon,
  Box,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';

interface SurveyData {
  name: string;
  email: string;
  satisfaction: string;
  features: string[];
  comments: string;
}

interface Props {
  /** Available feature options for the checkbox step */
  featureOptions: string[];
  /** Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied) */
  satisfactionLabels: string[];
  /** Action Callback for final submission */
  onSubmit?: (data: SurveyData) => void;
}

/**
 * A multi-step survey form with progress tracking and response review.
 */
export default function SurveyForm({
  featureOptions = ['Mobile App', 'Dashboard', 'API Access', 'Reporting', 'Automation'],
  satisfactionLabels = ['Extremely Unsatisfied', 'Unsatisfied', 'Neutral', 'Satisfied', 'Extremely Satisfied'],
  onSubmit
}: Props) {
  const { motionEnabled } = useMotion();
  const [step, setStep] = useState(0);
  const [done, setDone] = useState(false);
  const [loading, setLoading] = useState(false);
  const [data, setData] = useState<SurveyData>({
    name: '',
    email: '',
    satisfaction: '',
    features: [],
    comments: '',
  });

  const next = () => setStep(s => s + 1);
  const back = () => setStep(s => s - 1);

  const isValidEmail = (e: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e);
  const canNext = step === 0 ? data.name.length > 0 && isValidEmail(data.email) : step === 1 ? !!data.satisfaction : true;

  const submit = async () => {
    setLoading(true);
    try {
      if (onSubmit) await onSubmit(data);
      setDone(true);
    } catch (e) {
      console.error(e);
    } finally {
      setLoading(false);
    }
  };

  if (done) {
    return (
      <Container maxWidth="sm">
        <Card padding={32}>
          <Stack align="center" gap={24}>
            <Icon name="check" size={64} color="var(--ggui-color-success-500, #22c55e)" />
            <Stack gap={8} align="center">
              <Text variant="h2">Survey Complete</Text>
              <Text align="center" color="var(--ggui-color-onSurfaceVariant, #52525b)">Your feedback has been successfully submitted. Thank you!</Text>
            </Stack>
            <Button variant="primary" onClick={() => setDone(false)}>Close</Button>
          </Stack>
        </Card>
      </Container>
    );
  }

  const progress = ((step + 1) / 5) * 100;

  return (
    <Container maxWidth="sm">
      <MotionKeyframes />
      <Card padding={24} shadow="md" border>
        <Stack gap={24} role="form" aria-label="Survey Form">
          <Text variant="h2" align="center">Customer Feedback</Text>
          <Box>
            <Text variant="caption" weight="semibold" color="var(--ggui-color-onSurfaceVariant, #52525b)">Step {step + 1} of 5</Text>
            <div style={{ height: 4, width: '100%', background: 'var(--ggui-color-outlineVariant, #e4e4e7)', marginTop: 8, borderRadius: 2, overflow: 'hidden' }}>
              <div style={{ height: '100%', width: `${progress}%`, background: 'var(--ggui-color-primary-600, #0284c7)', transition: 'width 0.3s ease' }} />
            </div>
          </Box>

          {step === 0 && (
            <Stack gap={16}>
              <Box>
                <Text variant="label">Full Name</Text>
                <Input label="Full Name" value={data.name} onChange={v => setData({...data, name: v})} placeholder="John Doe" />
              </Box>
              <Box>
                <Text variant="label">Email Address</Text>
                <Input label="Email Address" type="email" value={data.email} onChange={v => setData({...data, email: v})} placeholder="name@example.com" />
              </Box>
            </Stack>
          )}

          {step === 1 && (
            <RadioGroup
              label="Overall Satisfaction"
              value={data.satisfaction}
              onChange={v => setData({...data, satisfaction: v})}
              options={satisfactionLabels.slice(0, 5).map((l, i) => ({ value: (i+1).toString(), label: l }))}
            />
          )}

          {step === 2 && (
            <Stack gap={12}>
              <Text variant="h3">Feature Interests</Text>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">Select features you'd like to see:</Text>
              {featureOptions.map(f => (
                <Checkbox key={f} label={f} checked={data.features.includes(f)} onChange={c => {
                  const n = c ? [...data.features, f] : data.features.filter(x => x !== f);
                  setData({...data, features: n});
                }} />
              ))}
            </Stack>
          )}

          {step === 3 && (
            <Box>
              <Text variant="label">Additional Comments</Text>
              <TextArea label="Additional Comments" value={data.comments} onChange={v => setData({...data, comments: v})} maxLength={500} placeholder="Any thoughts?" />
              <Text variant="caption" align="right">{data.comments.length}/500</Text>
            </Box>
          )}

          {step === 4 && (
            <Stack gap={16}>
              <Text variant="h3">Review Summary</Text>
              <Card padding={16} background="var(--ggui-color-surfaceVariant, #f4f4f5)" border={false}>
                <Stack gap={12}>
                  <Text variant="bodySmall"><strong>Name:</strong> {data.name}</Text>
                  <Text variant="bodySmall"><strong>Email:</strong> {data.email}</Text>
                  <Text variant="bodySmall"><strong>Rating:</strong> {satisfactionLabels[parseInt(data.satisfaction)-1] || 'None'}</Text>
                  <Text variant="bodySmall"><strong>Features:</strong> {data.features.join(', ') || 'None'}</Text>
                  <Text variant="bodySmall"><strong>Comments:</strong> {data.comments || 'No comments'}</Text>
                </Stack>
              </Card>
            </Stack>
          )}

          <Divider />
          <Row justify="between">
            <Button variant="ghost" onClick={back} disabled={step === 0 || loading}>Back</Button>
            {step < 4 ? (
              <Button variant="primary" onClick={next} disabled={!canNext}>Next</Button>
            ) : (
              <Button variant="primary" onClick={submit} loading={loading} disabled={loading}>Finish</Button>
            )}
          </Row>
        </Stack>
      </Card>
    </Container>
  );
}

import React, { useState, useMemo } from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Box,
  Divider,
  Badge,
  MotionKeyframes
} from '@ggui-ai/design/primitives';
import { transition, animation } from '@ggui-ai/design/tokens';

interface ElementData {
  atomicNumber?: number;
  symbol?: string;
  name?: string;
  atomicWeight?: number;
  category?: string;
  row?: number;
  col?: number;
}

interface Props {
  /** Full periodic table element data */
  elements: ElementData[];
}

const getCategoryColors = (category: string = '') => {
  const c = category.toLowerCase();
  if (c.includes('alkali metal')) return { bg: 'var(--ggui-color-error-50, #fef2f2)', border: 'var(--ggui-color-error-200, #fecaca)', text: 'var(--ggui-color-error-700, #b91c1c)' };
  if (c.includes('alkaline earth')) return { bg: 'var(--ggui-color-warning-50, #fffbeb)', border: 'var(--ggui-color-warning-200, #fef3c7)', text: 'var(--ggui-color-warning-700, #b45309)' };
  if (c.includes('transition metal')) return { bg: 'var(--ggui-color-neutral-100, #f3f4f6)', border: 'var(--ggui-color-neutral-300, #d1d5db)', text: 'var(--ggui-color-neutral-700, #374151)' };
  if (c.includes('post-transition')) return { bg: 'var(--ggui-color-success-50, #f0fdf4)', border: 'var(--ggui-color-success-200, #bbf7d0)', text: 'var(--ggui-color-success-700, #15803d)' };
  if (c.includes('metalloid')) return { bg: 'var(--ggui-color-warning-100, #fef3c7)', border: 'var(--ggui-color-warning-300, #fcd34d)', text: 'var(--ggui-color-warning-800, #92400e)' };
  if (c.includes('nonmetal')) return { bg: 'var(--ggui-color-primary-50, #f0f9ff)', border: 'var(--ggui-color-primary-200, #bae6fd)', text: 'var(--ggui-color-primary-700, #0369a1)' };
  if (c.includes('noble gas')) return { bg: 'var(--ggui-color-primary-100, #e0f2fe)', border: 'var(--ggui-color-primary-400, #38bdf8)', text: 'var(--ggui-color-primary-900, #0c4a6e)' };
  if (c.includes('lanthanide')) return { bg: 'var(--ggui-color-neutral-50, #f9fafb)', border: 'var(--ggui-color-neutral-200, #e5e7eb)', text: 'var(--ggui-color-neutral-600, #4b5563)' };
  if (c.includes('actinide')) return { bg: 'var(--ggui-color-neutral-200, #e5e7eb)', border: 'var(--ggui-color-neutral-400, #9ca3af)', text: 'var(--ggui-color-neutral-800, #1f2937)' };
  if (c.includes('halogen')) return { bg: 'var(--ggui-color-info-50, #ecfeff)', border: 'var(--ggui-color-info-200, #a5f3fc)', text: 'var(--ggui-color-info-700, #0e7490)' };
  return { bg: 'var(--ggui-color-surfaceVariant, #f4f4f5)', border: 'var(--ggui-color-outline, #d4d4d8)', text: 'var(--ggui-color-onSurface, #18181b)' };
};

