import React, { useState, useEffect, useRef } from 'react';
import {
  Box,
  Card,
  Stack,
  Row,
  Text,
  Input,
  Button,
  Badge,
  MotionKeyframes,
  useMotion
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Props {
  /** Chat window title */
  title: string;
  /** Current user name */
  currentUser: string;
  /** Number of participants */
  participantCount?: number;
  /** Array of messages */
  messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
  /** Callback for sending message */
  sendMessage: (payload: { text: string; timestamp: string }) => void;
}

export default function ChatInterface(props: Props) {
  const { title, currentUser, participantCount, messages = [], sendMessage } = props;
  const [inputText, setInputText] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);
  const { motionEnabled } = useMotion();

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages]);

  const handleSend = () => {
    if (!inputText.trim()) return;
    sendMessage({ text: inputText, timestamp: new Date().toISOString() });
    setInputText('');
  };

  return (
    <Card padding={0} shadow="md" style={{ height: '600px', display: 'flex', flexDirection: 'column', border: '1px solid var(--ggui-color-outline, #d4d4d8)', background: 'var(--ggui-color-surface, #fafafa)' }}>
      <MotionKeyframes />
      <Box padding="var(--ggui-spacing-4, 16px)" style={{ borderBottom: '1px solid var(--ggui-color-outline, #d4d4d8)' }}>
        <Row align="center" gap={12}>
          <Text variant="h3" weight="bold">{title}</Text>
          {participantCount !== undefined && <Badge variant="primary" size="sm">{participantCount}</Badge>}
        </Row>
      </Box>

      <Box ref={scrollRef} padding="var(--ggui-spacing-4, 16px)" style={{ flex: 1, overflowY: 'auto' }}>
        <Stack gap={16}>
          {messages.map((m, i) => {
            const isMe = m.sender === currentUser;
            const isFirst = i === 0 || messages[i - 1].sender !== m.sender;
            return (
              <Stack key={i} align={isMe ? 'end' : 'start'} gap={4} style={{ animation: motionEnabled ? animation.fadeIn : 'none', alignSelf: isMe ? 'flex-end' : 'flex-start', maxWidth: '80%' }}>
                {isFirst && !isMe && <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">{m.sender}</Text>}
                <Box padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)" borderRadius="var(--ggui-shape-radius-lg, 12px)" style={{ backgroundColor: isMe ? 'var(--ggui-color-primary-600, #0284c7)' : 'var(--ggui-color-surfaceVariant, #f4f4f5)', color: isMe ? 'var(--ggui-color-surface, #ffffff)' : 'var(--ggui-color-onSurface, #18181b)' }}>
                  <Text style={{ color: 'inherit' }}>{m.text}</Text>
                </Box>
                <Text variant="caption" style={{ opacity: 0.7 }}>{m.timestamp ? new Date(m.timestamp).toLocaleTimeString() : ''}</Text>
              </Stack>
            );
          })}
        </Stack>
      </Box>

      <Box padding="var(--ggui-spacing-4, 16px)" style={{ borderTop: '1px solid var(--ggui-color-outline, #d4d4d8)' }}>
        <Row gap={12} align="center">
          <Input label="Message" value={inputText} onChange={setInputText} placeholder="Type..." />
          <Button variant="primary" disabled={!inputText.trim()} onClick={handleSend}>Send Message</Button>
        </Row>
      </Box>
    </Card>
  );
}

import React from 'react';
import {
  Container,
  Card,
  Stack,
  Row,
  Text,
  Icon,
  MotionKeyframes,
  Spacer,
  Box
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Stock {
  symbol?: string;
  name?: string;
  price?: number;
  change?: number;
  changePercent?: number;
}

interface Props {
  /** Array of stocks with symbol, name, price, change, changePercent */
  stocks: Array<Stock>;
  /** ISO timestamp of last price update */
  lastUpdated?: string;
}

/**
 * MarketWatchDashboard Component
 * 
 * Displays a real-time stock ticker grid.
 * Reacts to prop changes for live updates (Broadcast/Stream Contract).
 */
export default function MarketWatchDashboard({
  stocks = [],
  lastUpdated
}: Props) {

  const formatTime = (iso?: string) => {
    if (!iso) return 'Live';
    try {
      const d = new Date(iso);
      return d.toLocaleTimeString([], { 
        hour: '2-digit', 
        minute: '2-digit', 
        second: '2-digit' 
      });
    } catch {
      return iso;
    }
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6, 24px)">
      <MotionKeyframes />
      <Stack gap={32}>
        {/* Header Section */}
        <Row align="center" justify="between" wrap>
          <Stack gap={4}>
            <Text variant="h2" weight="bold">Market Watch</Text>
            <Row align="center" gap={8}>
              <Box
                style={{
                  width: 8,
                  height: 8,
                  borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                  backgroundColor: 'var(--ggui-color-success-500, #22c55e)',
                  boxShadow: '0 0 8px var(--ggui-color-success-300)',
                }}
              />
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {lastUpdated ? `Updated ${formatTime(lastUpdated)}` : 'Real-time Feed Active'}
              </Text>
            </Row>
          </Stack>
        </Row>

        {/* Stock Grid: 3 columns desktop, 1 column mobile */}
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))',
          gap: 'var(--ggui-spacing-6, 24px)',
          width: '100%'
        }}>
          {stocks.map((stock, index) => {
            const isPositive = (stock.change ?? 0) >= 0;
            const color = isPositive 
              ? 'var(--ggui-color-success-600, #16a34a)' 
              : 'var(--ggui-color-error-600, #dc2626)';

            return (
              <Card 
                key={stock.symbol || index} 
                padding={24}
                style={{
                  borderLeft: `4px solid ${color}`,
                  backgroundColor: 'var(--ggui-color-surface, #fafafa)',
                  animation: animation.fadeIn,
                  // Use transition for color changes if price updates in place
                  transition: `border-color ${transition.normal}`,
                }}
              >
                <Stack gap={16}>
                  <Row justify="between" align="start">
                    <Stack gap={2}>
                      <Text variant="h3" weight="bold">
                        {stock.symbol || '---'}
                      </Text>
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        {stock.name || 'Stock Asset'}
                      </Text>
                    </Stack>
                    <Box style={{ 
                      padding: 'var(--ggui-spacing-1, 4px)', 
                      borderRadius: 'var(--ggui-shape-radius-sm, 4px)',
                      background: isPositive ? 'var(--ggui-color-success-50, #f0fdf4)' : 'var(--ggui-color-error-50, #fef2f2)'
                    }}>
                      <Icon 
                        name={isPositive ? 'chevron-up' : 'chevron-down'} 
                        color={color} 
                        size={18}
                      />
                    </Box>
                  </Row>

                  <Row justify="between" align="end">
                    <Stack gap={0}>
                      <Text variant="caption" weight="medium" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                        PRICE
                      </Text>
                      <Text variant="h2" weight="bold">
                        ${(stock.price ?? 0).toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 })}
                      </Text>
                    </Stack>

                    <Stack align="end" gap={0}>
                      <Text 
                        weight="bold" 
                        color={color}
                        variant="body"
                      >
                        {isPositive ? '+' : ''}{(stock.change ?? 0).toFixed(2)}
                      </Text>
                      <Text 
                        variant="caption" 
                        weight="bold"
                        color={color}
                        style={{ opacity: 0.8 }}
                      >
                        ({isPositive ? '+' : ''}{(stock.changePercent ?? 0).toFixed(2)}%)
                      </Text>
                    </Stack>
                  </Row>
                </Stack>
              </Card>
            );
          })}

          {stocks.length === 0 && (
            <Box 
              style={{ 
                gridColumn: '1 / -1', 
                textAlign: 'center', 
                padding: 'var(--ggui-spacing-12, 48px)',
                backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
                border: '1px dashed var(--ggui-color-outline, #d4d4d8)'
              }}
            >
              <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Waiting for data from market stream...
              </Text>
            </Box>
          )}
        </div>
      </Stack>
    </Container>
  );
}

import React, { useState } from 'react';
import { 
  Container, Card, Stack, Row, Text, Input, Select, Checkbox, RadioGroup, Button, Divider, Icon, MotionKeyframes, useMotion, Box
} from '@ggui-ai/design/primitives';
import { animation, transition } from '@ggui-ai/design/tokens';

interface Props {
  avatarOptions: string[];
  roleOptions: string[];
  initialProfile?: { 
    name?: string; email?: string; avatar?: string; role?: string; emailNotifications?: boolean; theme?: string 
  };
  onComplete?: (data: any) => void;
}

export default function OnboardingWizard(props: Props) {
  const { avatarOptions = ['👤', '🚀', '🌟', '🎨'], roleOptions = ['Developer', 'Designer', 'Manager', 'Other'], initialProfile = {}, onComplete } = props;
  const { motionEnabled } = useMotion();

  const [currentStep, setCurrentStep] = useState(0);
  const [formData, setFormData] = useState({
    name: initialProfile.name ?? '',
    email: initialProfile.email ?? '',
    avatar: initialProfile.avatar ?? (avatarOptions[0] || '👤'),
    role: initialProfile.role ?? '',
    emailNotifications: initialProfile.emailNotifications ?? true,
    theme: initialProfile.theme ?? 'light',
  });

  const [touched, setTouched] = useState<Record<string, boolean>>({});

  const validateEmail = (e: string) => /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(e);
  const isStep1Valid = formData.name.trim().length > 0 && validateEmail(formData.email);
  const isStep2Valid = formData.role !== '';

  const update = (f: string, v: any) => setFormData(p => ({ ...p, [f]: v }));

  const next = () => {
    setTouched({ name: true, email: true });
    if (currentStep === 0 && !isStep1Valid) return;
    if (currentStep === 1 && !isStep2Valid) return;
    setCurrentStep(s => s + 1);
  };

  return (
    <Container maxWidth="md" padding="var(--ggui-spacing-8, 32px)">
      <MotionKeyframes />
      <Stack gap={32}>
        <Stack align="center" gap={8}>
          <Text variant="h2" weight="bold">Set Up Your Profile</Text>
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">Let's get started with your account.</Text>
        </Stack>

        <Card padding={32} shadow="md">
          <div key={currentStep} style={{ animation: motionEnabled ? animation.fadeIn : 'none', minHeight: '300px' }}>
            {currentStep === 0 && (
              <Stack gap={24}>
                <Text variant="h3">Step 1: Profile</Text>
                <Input label="Display Name" value={formData.name} onChange={v => update('name', v)} required placeholder="Jane Doe" error={touched.name && !formData.name ? 'Required' : ''} />
                <Input label="Email Address" value={formData.email} onChange={v => update('email', v)} required placeholder="jane@example.com" error={touched.email && !validateEmail(formData.email) ? 'Invalid email' : ''} />
                <Stack gap={12}>
                  <Text variant="label">Avatar Emoji</Text>
                  <Row gap={12}>
                    {avatarOptions.map(a => (
                      <Button key={a} variant={formData.avatar === a ? 'primary' : 'outline'} onClick={() => update('avatar', a)}>{a}</Button>
                    ))}
                  </Row>
                </Stack>
              </Stack>
            )}

            {currentStep === 1 && (
              <Stack gap={24}>
                <Text variant="h3">Step 2: Preferences</Text>
                <Select label="User Role" value={formData.role} onChange={v => update('role', v)} options={roleOptions.map(r => ({ label: r, value: r }))} required placeholder="Select a role" />
                <Checkbox label="Enable Notifications" checked={formData.emailNotifications} onChange={v => update('emailNotifications', v)} description="Receive updates via email." />
                <RadioGroup label="Visual Theme" value={formData.theme} onChange={v => update('theme', v)} options={[{label:'Light',value:'light'},{label:'Dark',value:'dark'}]} direction="horizontal" />
              </Stack>
            )}

            {currentStep === 2 && (
              <Stack gap={24}>
                <Text variant="h3">Step 3: Review</Text>
                <Box padding={24} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius={12}>
                  <Stack gap={16}>
                    <Row gap={16} align="center">
                      <Box style={{ fontSize: '40px' }}>{formData.avatar}</Box>
                      <Stack gap={0}>
                        <Text weight="bold" variant="h3">{formData.name}</Text>
                        <Text variant="caption">{formData.email}</Text>
                      </Stack>
                    </Row>
                    <Divider />
                    <Stack gap={8}>
                      <Row justify="between"><Text color="var(--ggui-color-onSurfaceVariant, #52525b)">Role</Text><Text weight="medium">{formData.role}</Text></Row>
                      <Row justify="between"><Text color="var(--ggui-color-onSurfaceVariant, #52525b)">Notifications</Text><Text weight="medium">{formData.emailNotifications ? 'Yes' : 'No'}</Text></Row>
                      <Row justify="between"><Text color="var(--ggui-color-onSurfaceVariant, #52525b)">Theme</Text><Text weight="medium">{formData.theme === 'light' ? 'Light' : 'Dark'}</Text></Row>
                    </Stack>
                  </Stack>
                </Box>
              </Stack>
            )}
          </div>

          <Divider margin={24} />
          <Row justify="between">
            {currentStep > 0 ? <Button variant="outline" onClick={() => setCurrentStep(s => s - 1)} leftIcon={<Icon name="chevron-left" size={16} />}>Back</Button> : <div />}
            {currentStep < 2 ? (
              <Button variant="primary" onClick={next} disabled={currentStep === 0 ? !isStep1Valid : !isStep2Valid} rightIcon={<Icon name="chevron-right" size={16} />}>Continue</Button>
            ) : (
              <Button variant="primary" onClick={() => onComplete?.(formData)} leftIcon={<Icon name="check" size={16} />}>Complete Setup</Button>
            )}
          </Row>
        </Card>

        <Text align="center" variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          Step {currentStep + 1} of 3
        </Text>
      </Stack>
    </Container>
  );
}

import { Card, Stack, Row, Box, Text, Divider } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

const getConditionIcon = (conditionValue: string): string => {
  const normalized = conditionValue.toLowerCase();

  if (normalized.includes('sunny') || normalized.includes('clear')) return '☀️';
  if (normalized.includes('cloudy') || normalized.includes('overcast')) return '☁️';
  if (normalized.includes('rainy') || normalized.includes('drizzle') || normalized.includes('rain')) return '🌧️';
  if (normalized.includes('storm') || normalized.includes('thunder')) return '⛈️';
  if (normalized.includes('snow')) return '❄️';

  return '🌤️';
};

export default function GeneratedComponent({
  city = '',
  temperature = 0,
  condition = '',
  humidity = 0,
  windSpeed = 0,
  unit = 'C',
  forecast = [],
}: Props) {
  const displayUnit = unit || 'C';
  const displayTemp = `${temperature}°${displayUnit}`;
  const conditionText = condition || '—';
  const humidityText = `${humidity}%`;
  const windText = `${windSpeed} ${displayUnit === 'F' ? 'mph' : 'km/h'}`;
  const conditionIcon = getConditionIcon(conditionText);
  const forecastItems = forecast.slice(0, 5);

  return (
    <Card
      padding={24}
      shadow="md"
      border
      role="region"
      aria-label={`Weather for ${city || '—'}`}
      style={{
        background: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
        borderRadius: 'var(--ggui-shape-radius-lg, 12px)',
      }}
    >
      <Stack direction="vertical" gap={16}>
        <Row direction="horizontal" justify="between" align="start">
          <Stack direction="vertical" gap={8}>
            <Text
              variant="h3"
              weight="semibold"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {city || '—'}
            </Text>
            <Text
              variant="body"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              {conditionText}
            </Text>
          </Stack>

          <Text
            variant="h2"
            color="var(--ggui-color-primary-600, #0284c7)"
            aria-label={`Condition icon for ${conditionText}`}
          >
            {conditionIcon}
          </Text>
        </Row>

        <Text
          variant="h1"
          weight="bold"
          color="var(--ggui-color-primary-600, #0284c7)"
        >
          {displayTemp}
        </Text>

        <Row direction="horizontal" justify="between" align="stretch" wrap>
          <Box
            padding={8}
            borderRadius="var(--ggui-shape-radius-md, 8px)"
            style={{
              background: 'var(--ggui-color-surface, #fafafa)',
              border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
              minWidth: '140px',
            }}
          >
            <Stack direction="vertical" gap={4}>
              <Text
                variant="caption"
                weight="medium"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Humidity
              </Text>
              <Text
                variant="body"
                weight="semibold"
                color="var(--ggui-color-onSurface, #18181b)"
              >
                {humidityText}
              </Text>
            </Stack>
          </Box>

          <Box
            padding={8}
            borderRadius="var(--ggui-shape-radius-md, 8px)"
            style={{
              background: 'var(--ggui-color-surface, #fafafa)',
              border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
              minWidth: '140px',
            }}
          >
            <Stack direction="vertical" gap={4}>
              <Text
                variant="caption"
                weight="medium"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
              >
                Wind
              </Text>
              <Text
                variant="body"
                weight="semibold"
                color="var(--ggui-color-onSurface, #18181b)"
              >
                {windText}
              </Text>
            </Stack>
          </Box>
        </Row>

        <Divider />

        <Row
          direction="horizontal"
          justify="between"
          align="stretch"
          wrap
          aria-label="5-day forecast"
          style={{ gap: 'var(--ggui-spacing-2, 8px)' }}
        >
          {forecastItems.map((item, index) => {
            const day = item.day ?? '—';
            const icon = item.icon ?? getConditionIcon(conditionText);
            const high = item.high !== undefined ? `${item.high}°${displayUnit}` : '—';
            const low = item.low !== undefined ? `${item.low}°${displayUnit}` : '—';

            return (
              <Box
                key={`${day}-${index}`}
                padding={8}
                borderRadius="var(--ggui-shape-radius-md, 8px)"
                aria-label={`${day}, high ${high}, low ${low}`}
                style={{
                  background: 'var(--ggui-color-surface, #fafafa)',
                  border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
                  minWidth: '84px',
                }}
              >
                <Stack direction="vertical" gap={4} align="center">
                  <Text
                    variant="caption"
                    weight="medium"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    {day}
                  </Text>
                  <Text variant="body" color="var(--ggui-color-onSurface, #18181b)">
                    {icon}
                  </Text>
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    {`H ${high} / L ${low}`}
                  </Text>
                </Stack>
              </Box>
            );
          })}
        </Row>
      </Stack>
    </Card>
  );
}

import { Card, Stack, Row, Text, Badge, Divider, Box } from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

export default function GeneratedComponent({
  city = '',
  temperature = 0,
  condition = '',
  humidity = 0,
  windSpeed = 0,
  unit = 'C',
  forecast = [],
}: Props) {
  const displayTemp = `${temperature}°${unit}`;
  const displayCondition = condition;
  const displayHumidity = `${humidity}%`;
  const displayWind = `${windSpeed} ${unit === 'F' ? 'mph' : 'km/h'}`;

  const conditionIcons: Record<string, string> = {
    sunny: '☀️',
    clear: '☀️',
    cloudy: '☁️',
    overcast: '☁️',
    rainy: '🌧️',
    rain: '🌧️',
    stormy: '⛈️',
    thunderstorm: '⛈️',
    snowy: '❄️',
    snow: '❄️',
    windy: '💨',
    foggy: '🌫️',
    mist: '🌫️',
  };

  const conditionIcon =
    conditionIcons[(condition || '').trim().toLowerCase()] || '•';

  return (
    <Card
      padding={24}
      shadow="md"
      border
      aria-label={`Weather for ${city}`}
      style={{
        backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
        borderColor: 'var(--ggui-color-outlineVariant, #e4e4e7)',
      }}
    >
      <Stack direction="vertical" gap={16}>
        <Row justify="between" align="center" gap={8} wrap>
          <Text
            variant="h3"
            weight="semibold"
            color="var(--ggui-color-onSurface, #18181b)"
          >
            {city}
          </Text>
          <Row align="center" gap={8}>
            <Text
              variant="body"
              weight="medium"
              color="var(--ggui-color-primary-600, #0284c7)"
              aria-label={`Condition icon: ${displayCondition}`}
            >
              {conditionIcon}
            </Text>
            <Badge variant="info" size="sm" pill>
              {displayCondition}
            </Badge>
          </Row>
        </Row>

        <Stack direction="vertical" gap={4}>
          <Text
            variant="h1"
            weight="bold"
            color="var(--ggui-color-primary-600, #0284c7)"
          >
            {displayTemp}
          </Text>
          <Text
            variant="body"
            weight="medium"
            color="var(--ggui-color-onSurfaceVariant, #52525b)"
          >
            {displayCondition}
          </Text>
        </Stack>

        <Row gap={16} wrap>
          <Stack direction="vertical" gap={2}>
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Humidity
            </Text>
            <Text
              variant="body"
              weight="semibold"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {displayHumidity}
            </Text>
          </Stack>

          <Stack direction="vertical" gap={2}>
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant, #52525b)"
            >
              Wind
            </Text>
            <Text
              variant="body"
              weight="semibold"
              color="var(--ggui-color-onSurface, #18181b)"
            >
              {displayWind}
            </Text>
          </Stack>
        </Row>

        <Divider />

        <Box
          role="list"
          padding="var(--ggui-spacing-2, 8px)"
          background="var(--ggui-color-surface, #fafafa)"
          borderRadius="var(--ggui-shape-radius-lg, 12px)"
          style={{
            border: '1px solid var(--ggui-color-outlineVariant, #e4e4e7)',
          }}
        >
          <Row justify="between" align="center" gap={8} wrap>
            {forecast.slice(0, 5).map((item, index) => {
              const day = item.day ?? '—';
              const icon = item.icon ?? '•';
              const temps =
                item.high !== undefined && item.low !== undefined
                  ? `${item.high}° / ${item.low}°`
                  : '—/—';

              return (
                <Box
                  key={item.day || index}
                  role="listitem"
                  padding="var(--ggui-spacing-2, 8px)"
                  borderRadius="var(--ggui-shape-radius-md, 8px)"
                  style={{
                    transition:
                      'var(--ggui-transition-colors, color 200ms ease, background-color 200ms ease, border-color 200ms ease)',
                  }}
                >
                  <Stack direction="vertical" align="center" gap={4}>
                    <Text
                      variant="caption"
                      weight="medium"
                      color="var(--ggui-color-onSurfaceVariant, #52525b)"
                    >
                      {day}
                    </Text>
                    <Text
                      variant="body"
                      color="var(--ggui-color-primary-600, #0284c7)"
                      aria-label={`Forecast icon for ${day}`}
                    >
                      {icon}
                    </Text>
                    <Text
                      variant="caption"
                      color="var(--ggui-color-onSurface, #18181b)"
                    >
                      {temps}
                    </Text>
                  </Stack>
                </Box>
              );
            })}
          </Row>
        </Box>
      </Stack>
    </Card>
  );
}
